1	/* sno_engine.plsw -- SNOBOL4 interpreter: engine module
2	 * Lexer, parser, AM emitter, lowering, executor, pattern engine.
3	 * Compiled as library -- strip runtime before linking.
4	 */
5	
6	%DEFINE NOLISTING;
7	
8	%INCLUDE descr;
9	%INCLUDE heap;
10	%INCLUDE am;
11	%INCLUDE pat;
12	%INCLUDE snoglob;
13	
14	IS_A: PROC(C INT) RETURNS(INT);
15	    IF (C >= 65) THEN IF (C <= 90) THEN RETURN(1);
16	    IF (C >= 97) THEN IF (C <= 122) THEN RETURN(1);
17	    RETURN(0);
18	END;
19	
20	IS_D: PROC(C INT) RETURNS(INT);
21	    IF (C >= 48) THEN IF (C <= 57) THEN RETURN(1);
22	    RETURN(0);
23	END;
24	
25	IS_AN: PROC(C INT) RETURNS(INT);
26	    IF (IS_A(C) != 0) THEN RETURN(1);
27	    IF (IS_D(C) != 0) THEN RETURN(1);
28	    RETURN(0);
29	END;
30	
31	LEX: PROC;
32	    DCL C INT;
33	    DCL I INT;
34	    DCL Q INT;
35	    C = SRC(SPOS);
36	    IF (AT_SOL = 1) THEN DO;
37	        AT_SOL = 0;
38	        IF (C != 32 AND C != 9 AND C != 10 AND C != 0) THEN
39	            LHAS_LBL = 1;
40	        ELSE
41	            LHAS_LBL = 0;
42	    END;
43	    DO WHILE (C = 32 OR C = 9);
44	        SPOS = SPOS + 1;
45	        C = SRC(SPOS);
46	    END;
47	    IF (C = 0) THEN DO; TT = TK_EOF; RETURN; END;
48	    IF (C = 10) THEN DO; SPOS = SPOS + 1; TT = TK_EOL; AT_SOL = 1; RETURN; END;
49	    IF (C = 61) THEN DO; SPOS = SPOS + 1; TT = TK_EQ; RETURN; END;
50	    IF (C = 46) THEN DO; SPOS = SPOS + 1; TT = TK_DOT; RETURN; END;
51	    IF (C = 40) THEN DO; SPOS = SPOS + 1; TT = TK_LPAREN; RETURN; END;
52	    IF (C = 41) THEN DO; SPOS = SPOS + 1; TT = TK_RPAREN; RETURN; END;
53	    IF (C = 58) THEN DO; SPOS = SPOS + 1; TT = TK_COLON; RETURN; END;
54	    IF (C = 43) THEN DO; SPOS = SPOS + 1; TT = TK_PLUS; RETURN; END;
55	    IF (C = 45) THEN DO; SPOS = SPOS + 1; TT = TK_MINUS; RETURN; END;
56	    IF (C = 42) THEN DO; SPOS = SPOS + 1; TT = TK_STAR; RETURN; END;
57	    IF (C = 60) THEN DO; SPOS = SPOS + 1; TT = TK_LT; RETURN; END;
58	    IF (C = 62) THEN DO; SPOS = SPOS + 1; TT = TK_GT; RETURN; END;
59	    IF (C = 39 OR C = 34) THEN DO;
60	        Q = C;
61	        SPOS = SPOS + 1;
62	        I = 0;
63	        C = SRC(SPOS);
64	        DO WHILE (C != Q AND C != 0 AND C != 10);
65	            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
66	            SPOS = SPOS + 1;
67	            C = SRC(SPOS);
68	        END;
69	        IF (C = Q) THEN SPOS = SPOS + 1;
70	        TB(I) = 0;
71	        TN = I;
72	        TT = TK_STR;
73	        RETURN;
74	    END;
75	    IF (IS_D(C) != 0) THEN DO;
76	        TV = 0;
77	        DO WHILE (IS_D(SRC(SPOS)) != 0);
78	            C = SRC(SPOS);
79	            SPOS = SPOS + 1;
80	            TV = TV * 10 + (C - 48);
81	        END;
82	        TT = TK_INT;
83	        RETURN;
84	    END;
85	    IF (IS_A(C) != 0) THEN DO;
86	        I = 0;
87	        DO WHILE (IS_AN(SRC(SPOS)) != 0);
88	            C = SRC(SPOS);
89	            SPOS = SPOS + 1;
90	            IF (C >= 97) THEN IF (C <= 122) THEN C = C - 32;
91	            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
92	        END;
93	        TB(I) = 0;
94	        TN = I;
95	        TT = TK_IDENT;
96	        RETURN;
97	    END;
98	    /* Skip comment lines (starting with *) */
99	    IF (C = 42) THEN DO;
100	        DO WHILE (C != 10 AND C != 0);
101	            SPOS = SPOS + 1;
102	            C = SRC(SPOS);
103	        END;
104	        IF (C = 10) THEN DO; SPOS = SPOS + 1; AT_SOL = 1; END;
105	        TT = TK_EOL;
106	        RETURN;
107	    END;
108	    SPOS = SPOS + 1;
109	    TT = TK_EOF;
110	END;
111	
112	/* ================================================================
113	 * String helpers
114	 * ================================================================ */
115	
116	DCL SB(256) BYTE;
117	DCL SBPOS INT STATIC INIT(0);
118	
119	SBSAVE: PROC RETURNS(INT);
120	    DCL OFF INT;
121	    DCL I INT;
122	    DCL C INT;
123	    DCL DP PTR;
124	    OFF = SBPOS;
125	    I = 0;
126	    C = TB(0);
127	    DO WHILE (C != 0 AND I < 31);
128	        DP = ADDR(SB) + SBPOS;
129	        DP->DTAG = C;
130	        SBPOS = SBPOS + 1;
131	        I = I + 1;
132	        C = TB(I);
133	    END;
134	    DP = ADDR(SB) + SBPOS;
135	    DP->DTAG = 0;
136	    SBPOS = SBPOS + 1;
137	    RETURN(OFF);
138	END;
139	
140	SCEQ: PROC(A PTR, B PTR) RETURNS(INT);
141	    DCL I INT;
142	    DCL AP PTR;
143	    DCL BP PTR;
144	    DCL CA INT;
145	    DCL CB INT;
146	    I = 0;
147	    DO WHILE (1 = 1);
148	        AP = A + I;
149	        BP = B + I;
150	        CA = AP->DTAG;
151	        CB = BP->DTAG;
152	        IF (CA != CB) THEN RETURN(0);
153	        IF (CA = 0) THEN RETURN(1);
154	        I = I + 1;
155	    END;
156	    RETURN(1);
157	END;
158	
159	IS_END: PROC RETURNS(INT);
160	    IF (TB(0) = 69) THEN IF (TB(1) = 78) THEN IF (TB(2) = 68) THEN
161	        IF (TB(3) = 0) THEN RETURN(1);
162	    RETURN(0);
163	END;
164	
165	/* ================================================================
166	 * Symbol table
167	 * ================================================================ */
168	
169	%DEFINE SYMMAX 16;
170	
171	DCL SYMN(128) BYTE;
172	DCL SYMV(16) INT;
173	DCL SYMC INT STATIC INIT(0);
174	
175	SYM_FIND: PROC(NOFF INT) RETURNS(INT);
176	    DCL I INT;
177	    DCL NP PTR;
178	    I = 0;
179	    DO WHILE (I < SYMC);
180	        NP = ADDR(SYMN) + I * 8;
181	        IF (SCEQ(NP, ADDR(SB) + NOFF) != 0) THEN RETURN(I);
182	        I = I + 1;
183	    END;
184	    RETURN(0 - 1);
185	END;
186	
187	SYM_ADD: PROC(NOFF INT) RETURNS(INT);
188	    DCL IDX INT;
189	    DCL NP PTR;
190	    DCL SRP PTR;
191	    DCL I INT;
192	    DCL C INT;
193	    IF (SYMC >= SYMMAX) THEN RETURN(0 - 1);
194	    IDX = SYMC;
195	    NP = ADDR(SYMN) + IDX * 8;
196	    SRP = ADDR(SB) + NOFF;
197	    I = 0;
198	    C = 1;
199	    DO WHILE (C != 0 AND I < 7);
200	        DCL DP PTR;
201	        DCL RP PTR;
202	        RP = SRP + I;
203	        C = RP->DTAG;
204	        DP = NP + I;
205	        DP->DTAG = C;
206	        I = I + 1;
207	    END;
208	    DCL EP PTR;
209	    EP = NP + I;
210	    EP->DTAG = 0;
211	    SYMV(IDX) = 0;
212	    SYMC = SYMC + 1;
213	    RETURN(IDX);
214	END;
215	
