/* sno_engine.plsw -- SNOBOL4 interpreter: engine module
 * Lexer, parser, AM emitter, lowering, executor, pattern engine.
 * Compiled as library -- strip runtime before linking.
 */

%DEFINE NOLISTING;

%INCLUDE descr;
%INCLUDE heap;
%INCLUDE am;
%INCLUDE pat;
%INCLUDE snoglob;

IS_A: PROC(C INT) RETURNS(INT);
    IF (C >= 65) THEN IF (C <= 90) THEN RETURN(1);
    IF (C >= 97) THEN IF (C <= 122) THEN RETURN(1);
    RETURN(0);
END;

IS_D: PROC(C INT) RETURNS(INT);
    IF (C >= 48) THEN IF (C <= 57) THEN RETURN(1);
    RETURN(0);
END;

IS_AN: PROC(C INT) RETURNS(INT);
    IF (IS_A(C) != 0) THEN RETURN(1);
    IF (IS_D(C) != 0) THEN RETURN(1);
    RETURN(0);
END;

LEX: PROC;
    DCL C INT;
    DCL I INT;
    DCL Q INT;
    C = SRC(SPOS);
    IF (AT_SOL = 1) THEN DO;
        AT_SOL = 0;
        IF (C != 32 AND C != 9 AND C != 10 AND C != 0) THEN
            LHAS_LBL = 1;
        ELSE
            LHAS_LBL = 0;
    END;
    DO WHILE (C = 32 OR C = 9);
        SPOS = SPOS + 1;
        C = SRC(SPOS);
    END;
    IF (C = 0) THEN DO; TT = TK_EOF; RETURN; END;
    IF (C = 10) THEN DO; SPOS = SPOS + 1; TT = TK_EOL; AT_SOL = 1; RETURN; END;
    IF (C = 61) THEN DO; SPOS = SPOS + 1; TT = TK_EQ; RETURN; END;
    IF (C = 46) THEN DO; SPOS = SPOS + 1; TT = TK_DOT; RETURN; END;
    IF (C = 40) THEN DO; SPOS = SPOS + 1; TT = TK_LPAREN; RETURN; END;
    IF (C = 41) THEN DO; SPOS = SPOS + 1; TT = TK_RPAREN; RETURN; END;
    IF (C = 58) THEN DO; SPOS = SPOS + 1; TT = TK_COLON; RETURN; END;
    IF (C = 43) THEN DO; SPOS = SPOS + 1; TT = TK_PLUS; RETURN; END;
    IF (C = 45) THEN DO; SPOS = SPOS + 1; TT = TK_MINUS; RETURN; END;
    IF (C = 42) THEN DO; SPOS = SPOS + 1; TT = TK_STAR; RETURN; END;
    IF (C = 60) THEN DO; SPOS = SPOS + 1; TT = TK_LT; RETURN; END;
    IF (C = 62) THEN DO; SPOS = SPOS + 1; TT = TK_GT; RETURN; END;
    IF (C = 39 OR C = 34) THEN DO;
        Q = C;
        SPOS = SPOS + 1;
        I = 0;
        C = SRC(SPOS);
        DO WHILE (C != Q AND C != 0 AND C != 10);
            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
            SPOS = SPOS + 1;
            C = SRC(SPOS);
        END;
        IF (C = Q) THEN SPOS = SPOS + 1;
        TB(I) = 0;
        TN = I;
        TT = TK_STR;
        RETURN;
    END;
    IF (IS_D(C) != 0) THEN DO;
        TV = 0;
        DO WHILE (IS_D(SRC(SPOS)) != 0);
            C = SRC(SPOS);
            SPOS = SPOS + 1;
            TV = TV * 10 + (C - 48);
        END;
        TT = TK_INT;
        RETURN;
    END;
    IF (IS_A(C) != 0) THEN DO;
        I = 0;
        DO WHILE (IS_AN(SRC(SPOS)) != 0);
            C = SRC(SPOS);
            SPOS = SPOS + 1;
            IF (C >= 97) THEN IF (C <= 122) THEN C = C - 32;
            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
        END;
        TB(I) = 0;
        TN = I;
        TT = TK_IDENT;
        RETURN;
    END;
    /* Skip comment lines (starting with *) */
    IF (C = 42) THEN DO;
        DO WHILE (C != 10 AND C != 0);
            SPOS = SPOS + 1;
            C = SRC(SPOS);
        END;
        IF (C = 10) THEN DO; SPOS = SPOS + 1; AT_SOL = 1; END;
        TT = TK_EOL;
        RETURN;
    END;
    SPOS = SPOS + 1;
    TT = TK_EOF;
END;

/* ================================================================
 * String helpers
 * ================================================================ */

DCL SB(256) BYTE;
DCL SBPOS INT STATIC INIT(0);

SBSAVE: PROC RETURNS(INT);
    DCL OFF INT;
    DCL I INT;
    DCL C INT;
    DCL DP PTR;
    OFF = SBPOS;
    I = 0;
    C = TB(0);
    DO WHILE (C != 0 AND I < 31);
        DP = ADDR(SB) + SBPOS;
        DP->DTAG = C;
        SBPOS = SBPOS + 1;
        I = I + 1;
        C = TB(I);
    END;
    DP = ADDR(SB) + SBPOS;
    DP->DTAG = 0;
    SBPOS = SBPOS + 1;
    RETURN(OFF);
END;

SCEQ: PROC(A PTR, B PTR) RETURNS(INT);
    DCL I INT;
    DCL AP PTR;
    DCL BP PTR;
    DCL CA INT;
    DCL CB INT;
    I = 0;
    DO WHILE (1 = 1);
        AP = A + I;
        BP = B + I;
        CA = AP->DTAG;
        CB = BP->DTAG;
        IF (CA != CB) THEN RETURN(0);
        IF (CA = 0) THEN RETURN(1);
        I = I + 1;
    END;
    RETURN(1);
END;

IS_END: PROC RETURNS(INT);
    IF (TB(0) = 69) THEN IF (TB(1) = 78) THEN IF (TB(2) = 68) THEN
        IF (TB(3) = 0) THEN RETURN(1);
    RETURN(0);
END;

/* ================================================================
 * Symbol table
 * ================================================================ */

%DEFINE SYMMAX 16;

DCL SYMN(128) BYTE;
DCL SYMV(16) INT;
DCL SYMC INT STATIC INIT(0);

SYM_FIND: PROC(NOFF INT) RETURNS(INT);
    DCL I INT;
    DCL NP PTR;
    I = 0;
    DO WHILE (I < SYMC);
        NP = ADDR(SYMN) + I * 8;
        IF (SCEQ(NP, ADDR(SB) + NOFF) != 0) THEN RETURN(I);
        I = I + 1;
    END;
    RETURN(0 - 1);
END;

SYM_ADD: PROC(NOFF INT) RETURNS(INT);
    DCL IDX INT;
    DCL NP PTR;
    DCL SRP PTR;
    DCL I INT;
    DCL C INT;
    IF (SYMC >= SYMMAX) THEN RETURN(0 - 1);
    IDX = SYMC;
    NP = ADDR(SYMN) + IDX * 8;
    SRP = ADDR(SB) + NOFF;
    I = 0;
    C = 1;
    DO WHILE (C != 0 AND I < 7);
        DCL DP PTR;
        DCL RP PTR;
        RP = SRP + I;
        C = RP->DTAG;
        DP = NP + I;
        DP->DTAG = C;
        I = I + 1;
    END;
    DCL EP PTR;
    EP = NP + I;
    EP->DTAG = 0;
    SYMV(IDX) = 0;
    SYMC = SYMC + 1;
    RETURN(IDX);
END;

SYM_LOOKUP: PROC(NOFF INT) RETURNS(INT);
    DCL IDX INT;
    IDX = SYM_FIND(NOFF);
    IF (IDX >= 0) THEN RETURN(IDX);
    RETURN(SYM_ADD(NOFF));
END;

/* ================================================================
 * Label table
 * ================================================================ */

%DEFINE LBLMAX 8;

DCL LBLN(64) BYTE;
DCL LBLS(8) INT;
DCL LBLC INT STATIC INIT(0);

LBL_ADD: PROC(NOFF INT, STNUM INT);
    DCL NP PTR;
    DCL SRP PTR;
    DCL I INT;
    DCL C INT;
    IF (LBLC >= LBLMAX) THEN RETURN;
    NP = ADDR(LBLN) + LBLC * 8;
    SRP = ADDR(SB) + NOFF;
    I = 0;
    C = 1;
    DO WHILE (C != 0 AND I < 7);
        DCL DP PTR;
        DCL RP PTR;
        RP = SRP + I;
        C = RP->DTAG;
        DP = NP + I;
        DP->DTAG = C;
        I = I + 1;
    END;
    DCL EP PTR;
    EP = NP + I;
    EP->DTAG = 0;
    LBLS(LBLC) = STNUM;
    LBLC = LBLC + 1;
END;

LBL_FIND: PROC(NOFF INT) RETURNS(INT);
    DCL I INT;
    DCL NP PTR;
    I = 0;
    DO WHILE (I < LBLC);
        NP = ADDR(LBLN) + I * 8;
        IF (SCEQ(NP, ADDR(SB) + NOFF) != 0) THEN RETURN(LBLS(I));
        I = I + 1;
    END;
    RETURN(0 - 1);
END;

/* ================================================================
 * Statement table (max 16)
 * ================================================================ */

%DEFINE STMAX 16;

DCL S_TYP(16) INT;
DCL S_SUBJ(16) INT;
DCL S_SIDX(16) INT;
DCL S_OETY(16) INT;
DCL S_OEV1(16) INT;
DCL S_OEOP(16) INT;
DCL S_OEV2(16) INT;
DCL S_GTYP(16) INT;
DCL S_GLBL(16) INT;
DCL S_SPTR(16) INT;
DCL STCNT INT STATIC INIT(0);

/* Expression parts for concatenation: up to 4 parts per statement.
 * S_EPCNT(s) = number of parts (0 = use S_OETY/S_OEV1 as before).
 * EP_TYP(s*4+i) = part type (OE_INT, OE_STR, OE_IDENT).
 * EP_VAL(s*4+i) = part value (int, str offset, sym idx). */
DCL S_EPCNT(16) INT;
DCL EP_TYP(64) INT;
DCL EP_VAL(64) INT;

/* Pattern parts for compound match statements.
 * PP_TYP: OE_IDENT=var, OE_STR=literal, OE_SPAN, OE_BREAK, OE_REM, OE_CAP.
 * PP_VAL: sym idx, str offset, or class offset.
 * PP_VAL2: for OE_CAP = capture var idx. */

content.content:
300	 * PP_VAL2: for OE_CAP = capture var idx. */
301	%DEFINE OE_BREAK 6;
302	%DEFINE OE_REM 7;
303	%DEFINE OE_CAP 8;
304	%DEFINE OE_ARRAY 9;
305	%DEFINE OE_ARRREF 10;
306	DCL S_PPCNT(16) INT;
307	DCL PP_TYP(128) INT;
308	DCL PP_VAL(128) INT;
309	
310	/* ================================================================
311	 * Parser
312	 * ================================================================ */
313	
314	PARSE: PROC;
315	    DCL S INT;
316	    DCL NOFF INT;
317	    STCNT = 0;
318	    SBPOS = 0;
319	    SYMC = 0;
320	    LBLC = 0;
321	    SPOS = 0;
322	    AT_SOL = 1;
323	    CALL LEX;
324	
325	    DO WHILE (TT != TK_EOF AND STCNT < STMAX);
326	        S = STCNT;
327	        S_TYP(S) = ST_EMPTY;
328	        S_SUBJ(S) = 0 - 1;
329	        S_OETY(S) = OE_NONE;
330	        S_OEV1(S) = 0;
331	        S_OEOP(S) = 0;
332	        S_OEV2(S) = 0;
333	        S_GTYP(S) = GT_NONE;
334	        S_GLBL(S) = 0 - 1;
335	        S_SPTR(S) = 0 - 1;
336	        S_EPCNT(S) = 0;
337	        S_PPCNT(S) = 0;
338	        S_SIDX(S) = 0 - 1;
339	
340	        IF (TT = TK_EOL) THEN DO;
341	            CALL LEX;
342	            STCNT = STCNT + 1;
343	        END;
344	        ELSE IF (TT = TK_IDENT AND IS_END() != 0) THEN DO;
345	            S_TYP(S) = ST_END;
346	            NOFF = SBSAVE();
347	            CALL LBL_ADD(NOFF, S);
348	            CALL LEX;
349	            IF (TT = TK_EOL) THEN CALL LEX;
350	            STCNT = STCNT + 1;
351	        END;
352	        ELSE IF (TT = TK_IDENT) THEN DO;
353	            IF (LHAS_LBL = 1) THEN DO;
354	                NOFF = SBSAVE();
355	                CALL LBL_ADD(NOFF, S);
356	                CALL LEX;
357	            END;
358	
359	            IF (TT = TK_IDENT) THEN DO;
360	                NOFF = SBSAVE();
361	                S_SUBJ(S) = SYM_LOOKUP(NOFF);
362	                CALL LEX;
363	                /* Check for <index> (array element access) */
364	                IF (TT = TK_LT) THEN DO;
365	                    CALL LEX;
366	                    IF (TT = TK_IDENT) THEN DO;
367	                        NOFF = SBSAVE();
368	                        S_SIDX(S) = SYM_LOOKUP(NOFF);
369	                        CALL LEX;
370	                    END;
371	                    ELSE IF (TT = TK_INT) THEN DO;
372	                        /* Literal index -- store as negative (flag) */
373	                        S_SIDX(S) = 0 - TV - 1;
374	                        CALL LEX;
375	                    END;
376	                    IF (TT = TK_GT) THEN CALL LEX;
377	                END;
378	            END;
379	
380	            /* Check: is this a pattern match? (SUBJ parts... :goto)
381	             * If next token is IDENT (not =) or STR, it's a match stmt */
382	            IF ((TT = TK_IDENT OR TT = TK_STR) AND S_SUBJ(S) >= 0) THEN DO;
383	                DCL PPB INT;
384	                DCL PPI INT;
385	                S_TYP(S) = ST_MATCH;
386	                PPB = S * 8;
387	                PPI = 0;
388	
389	                /* Collect pattern parts until : or EOL */
390	                DO WHILE (TT != TK_COLON AND TT != TK_EOL AND TT != TK_EOF AND PPI < 8);
391	                    IF (TT = TK_DOT) THEN DO;
392	                        /* . CAPTURE */
393	                        CALL LEX;
394	                        IF (TT = TK_IDENT) THEN DO;
395	                            NOFF = SBSAVE();
396	                            PP_TYP(PPB + PPI) = OE_CAP;
397	                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
398	                            PPI = PPI + 1;
399	                            CALL LEX;
400	                        END;
401	                    END;
402	                    ELSE IF (TT = TK_STR) THEN DO;
403	                        PP_TYP(PPB + PPI) = OE_STR;
404	                        PP_VAL(PPB + PPI) = SBSAVE();
405	                        PPI = PPI + 1;
406	                        CALL LEX;
407	                    END;
408	                    ELSE IF (TT = TK_IDENT) THEN DO;
409	                        NOFF = SBSAVE();
410	                        /* Check for SPAN/BREAK/REM function */
411	                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
412	                            CALL LEX;
413	                            IF (TT = TK_LPAREN) THEN DO;
414	                                CALL LEX;
415	                                IF (TT = TK_STR) THEN DO;
416	                                    PP_TYP(PPB + PPI) = OE_SPAN;
417	                                    PP_VAL(PPB + PPI) = SBSAVE();
418	                                    PPI = PPI + 1;
419	                                    CALL LEX;
420	                                END;
421	                                IF (TT = TK_RPAREN) THEN CALL LEX;
422	                            END;
423	                        END;
424	                        ELSE IF (TB(0) = 66 AND TB(1) = 82 AND TB(2) = 69 AND TB(3) = 65 AND TB(4) = 75 AND TB(5) = 0) THEN DO;
425	                            CALL LEX;
426	                            IF (TT = TK_LPAREN) THEN DO;
427	                                CALL LEX;
428	                                IF (TT = TK_STR) THEN DO;
429	                                    PP_TYP(PPB + PPI) = OE_BREAK;
430	                                    PP_VAL(PPB + PPI) = SBSAVE();
431	                                    PPI = PPI + 1;
432	                                    CALL LEX;
433	                                END;
434	                                IF (TT = TK_RPAREN) THEN CALL LEX;
435	                            END;
436	                        END;
437	                        ELSE IF (TB(0) = 82 AND TB(1) = 69 AND TB(2) = 77 AND TB(3) = 0) THEN DO;
438	                            PP_TYP(PPB + PPI) = OE_REM;
439	                            PP_VAL(PPB + PPI) = 0;
440	                            PPI = PPI + 1;
441	                            CALL LEX;
442	                        END;
443	                        ELSE DO;
444	                            /* Pattern variable reference */
445	                            PP_TYP(PPB + PPI) = OE_IDENT;
446	                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
447	                            PPI = PPI + 1;
448	                            CALL LEX;
449	                        END;
450	                    END;
451	                    ELSE DO;
452	                        CALL LEX;
453	                    END;
454	                END;
455	
456	                S_PPCNT(S) = PPI;
457	            END;
458	            ELSE IF (TT = TK_EQ) THEN DO;
459	                DCL EPI INT;
460	                DCL EPB INT;
461	                S_TYP(S) = ST_ASSIGN;
462	                CALL LEX;
463	                EPB = S * 4;
464	                EPI = 0;
465	
466	                /* Collect expression parts */
467	                DO WHILE (TT = TK_INT OR TT = TK_STR OR TT = TK_IDENT);
468	                    IF (TT = TK_INT) THEN DO;
469	                        IF (EPI < 4) THEN DO;
470	                            EP_TYP(EPB + EPI) = OE_INT;
471	                            EP_VAL(EPB + EPI) = TV;
472	                            EPI = EPI + 1;
473	                        END;
474	                        CALL LEX;
475	                    END;
476	                    ELSE IF (TT = TK_STR) THEN DO;
477	                        IF (EPI < 4) THEN DO;
478	                            EP_TYP(EPB + EPI) = OE_STR;
479	                            EP_VAL(EPB + EPI) = SBSAVE();
480	                            EPI = EPI + 1;
481	                        END;
482	                        CALL LEX;
483	                    END;
484	                    ELSE IF (TT = TK_IDENT) THEN DO;
485	                        NOFF = SBSAVE();
486	                        /* Check for SPAN/ARRAY(...) */
487	                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
488	                            CALL LEX;
489	                            IF (TT = TK_LPAREN) THEN DO;
490	                                CALL LEX;
491	                                IF (TT = TK_STR) THEN DO;
492	                                    IF (EPI < 4) THEN DO;
493	                                        EP_TYP(EPB + EPI) = OE_SPAN;
494	                                        EP_VAL(EPB + EPI) = SBSAVE();
495	                                        EPI = EPI + 1;
496	                                    END;
497	                                    CALL LEX;
498	                                END;
499	                                IF (TT = TK_RPAREN) THEN CALL LEX;
500	                            END;
501	                        END;
502	                        ELSE IF (TB(0) = 65 AND TB(1) = 82 AND TB(2) = 82 AND TB(3) = 65 AND TB(4) = 89 AND TB(5) = 0) THEN DO;
503	                            /* ARRAY('1:50') */
504	                            CALL LEX;
505	                            IF (TT = TK_LPAREN) THEN DO;
506	                                CALL LEX;
507	                                IF (TT = TK_STR) THEN CALL LEX;
508	                                IF (TT = TK_RPAREN) THEN CALL LEX;
509	                            END;
510	                            IF (EPI < 4) THEN DO;
511	                                EP_TYP(EPB + EPI) = OE_ARRAY;
512	                                EP_VAL(EPB + EPI) = 0;
513	                                EPI = EPI + 1;
514	                            END;
515	                        END;
516	                        ELSE DO;
517	                            DCL SYMIDX INT;
518	                            SYMIDX = SYM_LOOKUP(NOFF);
519	                            CALL LEX;
520	                            /* Check for <index> (array ref in expr) */
521	                            IF (TT = TK_LT) THEN DO;
522	                                CALL LEX;
523	                                IF (EPI < 4) THEN DO;
524	                                    EP_TYP(EPB + EPI) = OE_ARRREF;
525	                                    EP_VAL(EPB + EPI) = SYMIDX;
526	                                    EPI = EPI + 1;
527	                                END;
528	                                /* Index: ident or int */
529	                                IF (TT = TK_IDENT) THEN DO;
530	                                    NOFF = SBSAVE();
531	                                    IF (EPI < 4) THEN DO;
532	                                        EP_TYP(EPB + EPI) = OE_IDENT;
533	                                        EP_VAL(EPB + EPI) = SYM_LOOKUP(NOFF);
534	                                        EPI = EPI + 1;
535	                                    END;
536	                                    CALL LEX;
537	                                END;
538	                                ELSE IF (TT = TK_INT) THEN DO;
539	                                    IF (EPI < 4) THEN DO;
540	                                        EP_TYP(EPB + EPI) = OE_INT;
541	                                        EP_VAL(EPB + EPI) = TV;
542	                                        EPI = EPI + 1;
543	                                    END;
544	                                    CALL LEX;
545	                                END;
546	                                IF (TT = TK_GT) THEN CALL LEX;
547	                            END;
548	                            ELSE DO;
549	                                IF (EPI < 4) THEN DO;
550	                                    EP_TYP(EPB + EPI) = OE_IDENT;
551	                                    EP_VAL(EPB + EPI) = SYMIDX;
552	                                    EPI = EPI + 1;
553	                                END;
554	                            END;
555	                        END;
556	                    END;
557	
558	                    /* Check for binary operator */
559	                    IF (TT = TK_PLUS OR TT = TK_MINUS OR TT = TK_STAR) THEN DO;
