 * PP_VAL2: for OE_CAP = capture var idx. */
%DEFINE OE_BREAK 6;
%DEFINE OE_REM 7;
%DEFINE OE_CAP 8;
%DEFINE OE_ARRAY 9;
%DEFINE OE_ARRREF 10;
DCL S_PPCNT(16) INT;
DCL PP_TYP(128) INT;
DCL PP_VAL(128) INT;

/* ================================================================
 * Parser
 * ================================================================ */

PARSE: PROC;
    DCL S INT;
    DCL NOFF INT;
    STCNT = 0;
    SBPOS = 0;
    SYMC = 0;
    LBLC = 0;
    SPOS = 0;
    AT_SOL = 1;
    CALL LEX;

    DO WHILE (TT != TK_EOF AND STCNT < STMAX);
        S = STCNT;
        S_TYP(S) = ST_EMPTY;
        S_SUBJ(S) = 0 - 1;
        S_OETY(S) = OE_NONE;
        S_OEV1(S) = 0;
        S_OEOP(S) = 0;
        S_OEV2(S) = 0;
        S_GTYP(S) = GT_NONE;
        S_GLBL(S) = 0 - 1;
        S_SPTR(S) = 0 - 1;
        S_EPCNT(S) = 0;
        S_PPCNT(S) = 0;
        S_SIDX(S) = 0 - 1;

        IF (TT = TK_EOL) THEN DO;
            CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE IF (TT = TK_IDENT AND IS_END() != 0) THEN DO;
            S_TYP(S) = ST_END;
            NOFF = SBSAVE();
            CALL LBL_ADD(NOFF, S);
            CALL LEX;
            IF (TT = TK_EOL) THEN CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE IF (TT = TK_IDENT) THEN DO;
            IF (LHAS_LBL = 1) THEN DO;
                NOFF = SBSAVE();
                CALL LBL_ADD(NOFF, S);
                CALL LEX;
            END;

            IF (TT = TK_IDENT) THEN DO;
                NOFF = SBSAVE();
                S_SUBJ(S) = SYM_LOOKUP(NOFF);
                CALL LEX;
                /* Check for <index> (array element access) */
                IF (TT = TK_LT) THEN DO;
                    CALL LEX;
                    IF (TT = TK_IDENT) THEN DO;
                        NOFF = SBSAVE();
                        S_SIDX(S) = SYM_LOOKUP(NOFF);
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_INT) THEN DO;
                        /* Literal index -- store as negative (flag) */
                        S_SIDX(S) = 0 - TV - 1;
                        CALL LEX;
                    END;
                    IF (TT = TK_GT) THEN CALL LEX;
                END;
            END;

            /* Check: is this a pattern match? (SUBJ parts... :goto)
             * If next token is IDENT (not =) or STR, it's a match stmt */
            IF ((TT = TK_IDENT OR TT = TK_STR) AND S_SUBJ(S) >= 0) THEN DO;
                DCL PPB INT;
                DCL PPI INT;
                S_TYP(S) = ST_MATCH;
                PPB = S * 8;
                PPI = 0;

                /* Collect pattern parts until : or EOL */
                DO WHILE (TT != TK_COLON AND TT != TK_EOL AND TT != TK_EOF AND PPI < 8);
                    IF (TT = TK_DOT) THEN DO;
                        /* . CAPTURE */
                        CALL LEX;
                        IF (TT = TK_IDENT) THEN DO;
                            NOFF = SBSAVE();
                            PP_TYP(PPB + PPI) = OE_CAP;
                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
                            PPI = PPI + 1;
                            CALL LEX;
                        END;
                    END;
                    ELSE IF (TT = TK_STR) THEN DO;
                        PP_TYP(PPB + PPI) = OE_STR;
                        PP_VAL(PPB + PPI) = SBSAVE();
                        PPI = PPI + 1;
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_IDENT) THEN DO;
                        NOFF = SBSAVE();
                        /* Check for SPAN/BREAK/REM function */
                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN DO;
                                    PP_TYP(PPB + PPI) = OE_SPAN;
                                    PP_VAL(PPB + PPI) = SBSAVE();
                                    PPI = PPI + 1;
                                    CALL LEX;
                                END;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                        END;
                        ELSE IF (TB(0) = 66 AND TB(1) = 82 AND TB(2) = 69 AND TB(3) = 65 AND TB(4) = 75 AND TB(5) = 0) THEN DO;
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN DO;
                                    PP_TYP(PPB + PPI) = OE_BREAK;
                                    PP_VAL(PPB + PPI) = SBSAVE();
                                    PPI = PPI + 1;
                                    CALL LEX;
                                END;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                        END;
                        ELSE IF (TB(0) = 82 AND TB(1) = 69 AND TB(2) = 77 AND TB(3) = 0) THEN DO;
                            PP_TYP(PPB + PPI) = OE_REM;
                            PP_VAL(PPB + PPI) = 0;
                            PPI = PPI + 1;
                            CALL LEX;
                        END;
                        ELSE DO;
                            /* Pattern variable reference */
                            PP_TYP(PPB + PPI) = OE_IDENT;
                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
                            PPI = PPI + 1;
                            CALL LEX;
                        END;
                    END;
                    ELSE DO;
                        CALL LEX;
                    END;
                END;

                S_PPCNT(S) = PPI;
            END;
            ELSE IF (TT = TK_EQ) THEN DO;
                DCL EPI INT;
                DCL EPB INT;
                S_TYP(S) = ST_ASSIGN;
                CALL LEX;
                EPB = S * 4;
                EPI = 0;

                /* Collect expression parts */
                DO WHILE (TT = TK_INT OR TT = TK_STR OR TT = TK_IDENT);
                    IF (TT = TK_INT) THEN DO;
                        IF (EPI < 4) THEN DO;
                            EP_TYP(EPB + EPI) = OE_INT;
                            EP_VAL(EPB + EPI) = TV;
                            EPI = EPI + 1;
                        END;
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_STR) THEN DO;
                        IF (EPI < 4) THEN DO;
                            EP_TYP(EPB + EPI) = OE_STR;
                            EP_VAL(EPB + EPI) = SBSAVE();
                            EPI = EPI + 1;
                        END;
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_IDENT) THEN DO;
                        NOFF = SBSAVE();
                        /* Check for SPAN/ARRAY(...) */
                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN DO;
                                    IF (EPI < 4) THEN DO;
                                        EP_TYP(EPB + EPI) = OE_SPAN;
                                        EP_VAL(EPB + EPI) = SBSAVE();
                                        EPI = EPI + 1;
                                    END;
                                    CALL LEX;
                                END;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                        END;
                        ELSE IF (TB(0) = 65 AND TB(1) = 82 AND TB(2) = 82 AND TB(3) = 65 AND TB(4) = 89 AND TB(5) = 0) THEN DO;
                            /* ARRAY('1:50') */
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN CALL LEX;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                            IF (EPI < 4) THEN DO;
                                EP_TYP(EPB + EPI) = OE_ARRAY;
                                EP_VAL(EPB + EPI) = 0;
                                EPI = EPI + 1;
                            END;
                        END;
                        ELSE DO;
                            DCL SYMIDX INT;
                            SYMIDX = SYM_LOOKUP(NOFF);
                            CALL LEX;
                            /* Check for <index> (array ref in expr) */
                            IF (TT = TK_LT) THEN DO;
                                CALL LEX;
                                IF (EPI < 4) THEN DO;
                                    EP_TYP(EPB + EPI) = OE_ARRREF;
                                    EP_VAL(EPB + EPI) = SYMIDX;
                                    EPI = EPI + 1;
                                END;
                                /* Index: ident or int */
                                IF (TT = TK_IDENT) THEN DO;
                                    NOFF = SBSAVE();
                                    IF (EPI < 4) THEN DO;
                                        EP_TYP(EPB + EPI) = OE_IDENT;
                                        EP_VAL(EPB + EPI) = SYM_LOOKUP(NOFF);
                                        EPI = EPI + 1;
                                    END;
                                    CALL LEX;
                                END;
                                ELSE IF (TT = TK_INT) THEN DO;
                                    IF (EPI < 4) THEN DO;
                                        EP_TYP(EPB + EPI) = OE_INT;
                                        EP_VAL(EPB + EPI) = TV;
                                        EPI = EPI + 1;
                                    END;
                                    CALL LEX;
                                END;
                                IF (TT = TK_GT) THEN CALL LEX;
                            END;
                            ELSE DO;
                                IF (EPI < 4) THEN DO;
                                    EP_TYP(EPB + EPI) = OE_IDENT;
                                    EP_VAL(EPB + EPI) = SYMIDX;
                                    EPI = EPI + 1;
                                END;
                            END;
                        END;
                    END;

                    /* Check for binary operator */
                    IF (TT = TK_PLUS OR TT = TK_MINUS OR TT = TK_STAR) THEN DO;
                        /* Store op, then parse second operand on next loop */
                        S_OEOP(S) = TT;
                        CALL LEX;
                    END;
                END;

                S_EPCNT(S) = EPI;
                /* For backward compat: if 1 part, set S_OETY/S_OEV1 */
                IF (EPI = 1) THEN DO;
                    S_OETY(S) = EP_TYP(EPB);
                    S_OEV1(S) = EP_VAL(EPB);
                    IF (S_OETY(S) = OE_STR OR S_OETY(S) = OE_SPAN) THEN
                        S_SPTR(S) = EP_VAL(EPB);
                END;
                ELSE IF (EPI = 2 AND S_OEOP(S) != 0) THEN DO;
                    /* Binary op: part0 OP part1 */
                    S_OETY(S) = OE_BINOP;
                    S_OEV1(S) = EP_VAL(EPB);
                    S_OEV2(S) = EP_VAL(EPB + 1);
                END;
                ELSE IF (EPI >= 2) THEN DO;
                    /* Concatenation */
                    S_OETY(S) = OE_NONE;
                END;
            END;

            IF (TT = TK_COLON) THEN DO;
                CALL LEX;
                IF (TT = TK_IDENT) THEN DO;
                    IF (TB(0) = 83 AND TB(1) = 0) THEN DO;
                        S_GTYP(S) = GT_SUCC;
                        CALL LEX;
                    END;
                    ELSE IF (TB(0) = 70 AND TB(1) = 0) THEN DO;
                        S_GTYP(S) = GT_FAIL;
                        CALL LEX;
                    END;
                END;
                ELSE IF (TT = TK_LPAREN) THEN DO;
                    S_GTYP(S) = GT_UNCOND;
                END;
                IF (TT = TK_LPAREN) THEN DO;
                    CALL LEX;
                    IF (TT = TK_IDENT) THEN DO;
                        S_GLBL(S) = SBSAVE();
                        CALL LEX;
                    END;
                    IF (TT = TK_RPAREN) THEN CALL LEX;
                END;
            END;

            DO WHILE (TT != TK_EOL AND TT != TK_EOF);
                CALL LEX;
            END;
            IF (TT = TK_EOL) THEN CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE DO;
            CALL LEX;
        END;
    END;
END;

/* ================================================================
 * AM code buffer + emitter
 * ================================================================ */

DCL AM_CODE(512) BYTE;
DCL AM_PC INT STATIC INIT(0);
DCL STMT_ADDR(16) INT;

AM_INIT: PROC;
    AM_PC = 0;
END;

AM_EMIT_OP: PROC(OP INT);
    AM_CODE(AM_PC) = OP;
    AM_PC = AM_PC + 1;
END;

AM_EMIT_BYTE: PROC(V INT);
    AM_CODE(AM_PC) = V;
    AM_PC = AM_PC + 1;
END;

AM_EMIT_WORD: PROC(V INT);
    DCL B0 INT;
    DCL B1 INT;
    DCL B2 INT;
    DCL REM INT;
    REM = V;
    B2 = 0;
    DO WHILE (REM > 65535);
        REM = REM - 65536;
        B2 = B2 + 1;
    END;
    B1 = 0;
    DO WHILE (REM > 255);
        REM = REM - 256;
        B1 = B1 + 1;
    END;
    B0 = REM;
    AM_CODE(AM_PC) = B0;
    AM_PC = AM_PC + 1;
    AM_CODE(AM_PC) = B1;
    AM_PC = AM_PC + 1;
    AM_CODE(AM_PC) = B2;
    AM_PC = AM_PC + 1;
END;

AM_PATCH_WORD: PROC(OFF INT, V INT);
    DCL B0 INT;
    DCL B1 INT;
    DCL B2 INT;
    DCL REM INT;
    REM = V;
    B2 = 0;
    DO WHILE (REM > 65535);
        REM = REM - 65536;
        B2 = B2 + 1;
    END;
    B1 = 0;
    DO WHILE (REM > 255);
        REM = REM - 256;
        B1 = B1 + 1;
    END;
    B0 = REM;
    AM_CODE(OFF) = B0;
    AM_CODE(OFF + 1) = B1;
    AM_CODE(OFF + 2) = B2;
END;

/* ================================================================
 * Lowering: statement table -> AM bytecode
 * ================================================================ */

DCL N_OUT(8) CHAR INIT('OUTPUT');
DCL N_INP(8) CHAR INIT('INPUT');
DCL OUT_SYM INT STATIC INIT(0);
DCL INP_SYM INT STATIC INIT(0);

/* Find OUTPUT and INPUT symbol indices */
FIND_SPECIAL: PROC;
    DCL I INT;
    DCL NP PTR;
    OUT_SYM = 0 - 1;
    INP_SYM = 0 - 1;
    I = 0;
    DO WHILE (I < SYMC);
        NP = ADDR(SYMN) + I * 8;
        IF (SCEQ(NP, ADDR(N_OUT)) != 0) THEN
            OUT_SYM = I;
        IF (SCEQ(NP, ADDR(N_INP)) != 0) THEN
            INP_SYM = I;
        I = I + 1;
    END;
END;

LOWER_STMT: PROC(S INT);
    DCL BR_OFF INT;
    DCL TGT INT;

    STMT_ADDR(S) = AM_PC;

    IF (S_TYP(S) = ST_END) THEN DO;
        CALL AM_EMIT_OP(OP_HALT);
        RETURN;
    END;

    IF (S_TYP(S) = ST_EMPTY) THEN DO;
        CALL AM_EMIT_OP(OP_NOP);
        RETURN;
    END;

    IF (S_TYP(S) = ST_ASSIGN) THEN DO;
        DCL EPI INT;
        DCL EPB INT;
        DCL EPT INT;
        DCL EPV INT;

        /* Evaluate object expression */
        IF (S_EPCNT(S) = 2 AND EP_TYP(S * 4) = OE_ARRREF) THEN DO;
            /* Array ref: NAMES<I> */
            EPB = S * 4;
            EPT = EP_TYP(EPB + 1);
            EPV = EP_VAL(EPB + 1);
            IF (EPT = OE_IDENT) THEN DO;
                CALL AM_EMIT_OP(OP_LOAD_VAR);
                CALL AM_EMIT_BYTE(EPV);
            END;

content.content:
750	            ELSE DO;
751	                CALL AM_EMIT_OP(OP_LOAD_INT);
752	                CALL AM_EMIT_WORD(EPV);
753	            END;
754	            CALL AM_EMIT_OP(OP_ARR_LOAD);
755	            CALL AM_EMIT_BYTE(EP_VAL(EPB));
756	        END;
757	        ELSE IF (S_EPCNT(S) >= 2 AND S_OEOP(S) = 0) THEN DO;
758	            /* Concatenation: emit parts with CONCAT between them */
759	            EPB = S * 4;
760	            EPI = 0;
761	            DO WHILE (EPI < S_EPCNT(S));
762	                EPT = EP_TYP(EPB + EPI);
763	                EPV = EP_VAL(EPB + EPI);
764	                IF (EPT = OE_INT) THEN DO;
765	                    CALL AM_EMIT_OP(OP_LOAD_INT);
766	                    CALL AM_EMIT_WORD(EPV);
767	                END;
768	                ELSE IF (EPT = OE_STR) THEN DO;
769	                    CALL AM_EMIT_OP(OP_LOAD_STR);
