1103	/* ================================================================
1104	 * Pattern matching primitives
1105	 * ================================================================ */
1106	
1107	/* Pattern values: stored in VARS as (type << 16 | data)
1108	 * Type 0 = integer, Type 1 = string offset, Type 2 = pattern (class offset)
1109	 * For SPAN, VARS[i] = 0x020000 | class_string_offset */
1110	
1111	%DEFINE VTYP_INT 0;
1112	%DEFINE VTYP_STR 1;
1113	%DEFINE VTYP_PAT 2;
1114	%DEFINE VTYP_ARR 3;
1115	
1116	/* Variable type tags (high byte of VARS entry for patterns) */
1117	DCL VTYP(16) INT;
1118	
1119	SLEN: PROC(S PTR) RETURNS(INT);
1120	    DCL I INT;
1121	    DCL P PTR;
1122	    I = 0;
1123	    P = S;
1124	    DO WHILE (P->DTAG != 0);
1125	        I = I + 1;
1126	        P = S + I;
1127	    END;
1128	    RETURN(I);
1129	END;
1130	
1131	IN_CLASS: PROC(C INT, CLASS PTR) RETURNS(INT);
1132	    DCL I INT;
1133	    DCL P PTR;
1134	    DCL CH INT;
1135	    I = 0;
1136	    P = CLASS;
1137	    CH = P->DTAG;
1138	    DO WHILE (CH != 0);
1139	        IF (CH = C) THEN RETURN(1);
1140	        I = I + 1;
1141	        P = CLASS + I;
1142	        CH = P->DTAG;
1143	    END;
1144	    RETURN(0);
1145	END;
1146	
1147	/* EXEC_SPAN: try SPAN match on subject at start_pos.
1148	 * Returns number of chars matched (0 = failure). */
1149	EXEC_SPAN: PROC(SUBJ PTR, SLEN2 INT, START INT, CLASS PTR) RETURNS(INT);
1150	    DCL POS INT;
1151	    DCL C INT;
1152	    DCL P PTR;
1153	    POS = START;
1154	    IF (POS >= SLEN2) THEN RETURN(0);
1155	    P = SUBJ + POS;
1156	    C = P->DTAG;
1157	    DO WHILE (C != 0 AND IN_CLASS(C, CLASS) != 0 AND POS < SLEN2);
1158	        POS = POS + 1;
1159	        IF (POS < SLEN2) THEN DO;
1160	            P = SUBJ + POS;
1161	            C = P->DTAG;
1162	        END;
1163	        ELSE C = 0;
1164	    END;
1165	    RETURN(POS - START);
1166	END;
1167	
1168	/* EXEC_BREAK: match up to (not including) first char in class.
1169	 * Returns number of chars consumed (0 is valid for BREAK). Fails if no class char found. */
1170	EXEC_BREAK: PROC(SUBJ PTR, SLEN2 INT, START INT, CLASS PTR) RETURNS(INT);
1171	    DCL POS INT;
1172	    DCL C INT;
1173	    DCL P PTR;
1174	    POS = START;
1175	    DO WHILE (POS < SLEN2);
1176	        P = SUBJ + POS;
1177	        C = P->DTAG;
1178	        IF (IN_CLASS(C, CLASS) != 0) THEN
1179	            RETURN(POS - START);
1180	        POS = POS + 1;
1181	    END;
1182	    /* No class char found = failure */
1183	    RETURN(0 - 1);
1184	END;
