1186	/* Pattern stack for building compound patterns at runtime.
1187	 * Each entry is an (kind, oper, next) triple stored as offsets. */
1188	DCL PSTK(16) INT;
1189	DCL PSTYP(16) INT;
1190	DCL PSTOP INT STATIC INIT(0);
1191	
1192	/* Last match result for :S/:F */
1193	DCL LAST_RESULT INT STATIC INIT(1);
1194	
1195	AM_EXEC: PROC;
1196	    DCL PC INT;
1197	    DCL OP INT;
1198	    DCL V INT;
1199	    DCL V2 INT;
1200	    DCL IDX INT;
1201	
1202	    PC = 0;
1203	    ESP = 0;
1204	
1205	    DO WHILE (PC < AM_PC);
1206	        OP = AM_CODE(PC);
1207	        PC = PC + 1;
1208	
1209	        IF (OP = OP_LOAD_INT) THEN DO;
1210	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1211	            PC = PC + 3;
1212	            ESTK(ESP) = V;
1213	            ESP = ESP + 1;
1214	            LAST_PUSH_TYP = VTYP_INT;
1215	        END;
1216	        ELSE IF (OP = OP_LOAD_STR) THEN DO;
1217	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1218	            PC = PC + 3;
1219	            ESTK(ESP) = V;
1220	            ESP = ESP + 1;
1221	            LAST_PUSH_TYP = VTYP_STR;
1222	        END;
1223	        ELSE IF (OP = OP_LOAD_VAR) THEN DO;
1224	            IDX = AM_CODE(PC);
1225	            PC = PC + 1;
1226	            ESTK(ESP) = VARS(IDX);
1227	            ESP = ESP + 1;
1228	            LAST_PUSH_TYP = VTYP(IDX);
1229	        END;
1230	        ELSE IF (OP = OP_STORE_VAR) THEN DO;
1231	            IDX = AM_CODE(PC);
1232	            PC = PC + 1;
1233	            ESP = ESP - 1;
1234	            VARS(IDX) = ESTK(ESP);
1235	            VTYP(IDX) = LAST_PUSH_TYP;
1236	        END;
1237	        ELSE IF (OP = OP_ADD) THEN DO;
1238	            ESP = ESP - 1;
1239	            V2 = ESTK(ESP);
1240	            ESP = ESP - 1;
1241	            ESTK(ESP) = ESTK(ESP) + V2;
1242	            ESP = ESP + 1;
1243	        END;
1244	        ELSE IF (OP = OP_SUB) THEN DO;
1245	            ESP = ESP - 1;
1246	            V2 = ESTK(ESP);
1247	            ESP = ESP - 1;
1248	            ESTK(ESP) = ESTK(ESP) - V2;
1249	            ESP = ESP + 1;
1250	        END;
1251	        ELSE IF (OP = OP_MUL) THEN DO;
1252	            ESP = ESP - 1;
1253	            V2 = ESTK(ESP);
1254	            ESP = ESP - 1;
1255	            ESTK(ESP) = ESTK(ESP) * V2;
1256	            ESP = ESP + 1;
1257	        END;
1258	        ELSE IF (OP = OP_CONCAT) THEN DO;
1259	            /* Pop two values, concat as strings into SB */
1260	            DCL DST INT;
1261	            DCL A_OFF INT;
1262	            DCL B_OFF INT;
1263	            DCL A_TYP INT;
1264	            DCL B_TYP INT;
1265	            DCL CP PTR;
1266	            DCL DP PTR;
1267	            DCL I INT;
1268	            DCL CH INT;
1269	
1270	            ESP = ESP - 1;
1271	            B_OFF = ESTK(ESP);
1272	            B_TYP = LAST_PUSH_TYP;
1273	            ESP = ESP - 1;
1274	            A_OFF = ESTK(ESP);
1275	            A_TYP = VTYP_STR;
1276	
1277	            DST = SBPOS;
1278	
1279	            /* Copy first value (A) as string */
1280	            IF (A_TYP = VTYP_STR OR A_TYP = VTYP_INT) THEN DO;
1281	                CP = ADDR(SB) + A_OFF;
1282	                CH = CP->DTAG;
1283	                I = 0;
1284	                DO WHILE (CH != 0 AND I < 60);
1285	                    DP = ADDR(SB) + SBPOS;
1286	                    DP->DTAG = CH;
1287	                    SBPOS = SBPOS + 1;
1288	                    I = I + 1;
1289	                    CP = ADDR(SB) + A_OFF + I;
1290	                    CH = CP->DTAG;
1291	                END;
1292	            END;
1293	
1294	            /* Copy second value (B) as string */
1295	            CP = ADDR(SB) + B_OFF;
1296	            CH = CP->DTAG;
1297	            I = 0;
1298	            DO WHILE (CH != 0 AND I < 60);
1299	                DP = ADDR(SB) + SBPOS;
1300	                DP->DTAG = CH;
1301	                SBPOS = SBPOS + 1;
1302	                I = I + 1;
1303	                CP = ADDR(SB) + B_OFF + I;
1304	                CH = CP->DTAG;
1305	            END;
1306	
1307	            /* Null terminate */
1308	            DP = ADDR(SB) + SBPOS;
1309	            DP->DTAG = 0;
1310	            SBPOS = SBPOS + 1;
1311	
1312	            ESTK(ESP) = DST;
1313	            ESP = ESP + 1;
1314	            LAST_PUSH_TYP = VTYP_STR;
1315	        END;
1316	        ELSE IF (OP = OP_PRINT_INT) THEN DO;
1317	            ESP = ESP - 1;
1318	            CALL PUT_DEC(ESTK(ESP));
1319	        END;
1320	        ELSE IF (OP = OP_PRINT_STR) THEN DO;
1321	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1322	            PC = PC + 3;
1323	            CALL UART_PUTS(ADDR(SB) + V);
1324	        END;
1325	        ELSE IF (OP = OP_PRINT_NL) THEN DO;
1326	            CALL UART_PUTS(ADDR(NL));
1327	        END;
1328	        ELSE IF (OP = OP_BR) THEN DO;
1329	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1330	            PC = V;
1331	        END;
1332	        ELSE IF (OP = OP_BR_SUCC) THEN DO;
1333	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1334	            IF (LAST_RESULT = 1) THEN
