1336	            ELSE
1337	                PC = PC + 3;
1338	        END;
1339	        ELSE IF (OP = OP_BR_FAIL) THEN DO;
1340	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1341	            IF (LAST_RESULT = 0) THEN
1342	                PC = V;
1343	            ELSE
1344	                PC = PC + 3;
1345	        END;
