1356	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1357	            PC = PC + 3;
1358	            /* Push to eval stack (for DIGITS = SPAN assignment) */
1359	            ESTK(ESP) = V;
1360	            ESP = ESP + 1;
1361	            LAST_PUSH_TYP = VTYP_PAT;
1362	            /* Also push to pattern stack (for compound match) */
1363	            PSTK(PSTOP) = V;
1364	            PSTYP(PSTOP) = PK_SPAN;
1365	            PSTOP = PSTOP + 1;
1366	        END;
1367	        ELSE IF (OP = OP_PAT_MATCH) THEN DO;
1368	            /* PAT_MATCH <subj_var> <pat_var> <cap_var> */
1369	            DCL SIDX INT;
1370	            DCL PIDX INT;
1371	            DCL CIDX INT;
1372	            DCL SUBJ_OFF INT;
1373	            DCL PAT_OFF INT;
1374	            DCL SUBJ_LEN INT;
1375	            DCL MATCHED INT;
1376	            DCL TRYPOS INT;
1377	            DCL MLEN INT;
1378	            DCL SP2 PTR;
1379	            DCL I INT;
1380	
1381	            SIDX = AM_CODE(PC);
1382	            PIDX = AM_CODE(PC + 1);
1383	            CIDX = AM_CODE(PC + 2);
1384	            PC = PC + 3;
1385	
1386	            /* Subject is a string offset in SB */
1387	            SUBJ_OFF = VARS(SIDX);
1388	            /* Pattern var holds class string offset (from MAKE_SPAN) */
1389	            PAT_OFF = VARS(PIDX);
1390	
1391	            /* Get subject length */
1392	            SUBJ_LEN = SLEN(ADDR(SB) + SUBJ_OFF);
1393	
1394	            /* Try SPAN at each position (unanchored) */
1395	            MATCHED = 0;
1396	            TRYPOS = 0;
1397	            DO WHILE (TRYPOS <= SUBJ_LEN AND MATCHED = 0);
1398	                MLEN = EXEC_SPAN(ADDR(SB) + SUBJ_OFF, SUBJ_LEN, TRYPOS, ADDR(SB) + PAT_OFF);
