1409	                            DCL DP PTR;
1410	                            DP = ADDR(SB) + SBPOS;
1411	                            DP->DTAG = SP2->DTAG;
1412	                            SBPOS = SBPOS + 1;
1413	                            I = I + 1;
1414	                        END;
1415	                        DP = ADDR(SB) + SBPOS;
1416	                        DP->DTAG = 0;
1417	                        SBPOS = SBPOS + 1;
1418	                        /* Store offset to captured string */
1419	                        VARS(CIDX) = DST;
1420	                        VTYP(CIDX) = VTYP_STR;
1421	                    END;
1422	                END;
1423	                TRYPOS = TRYPOS + 1;
1424	            END;
1425	
1426	            LAST_RESULT = MATCHED;
1427	        END;
1428	        ELSE IF (OP = OP_MAKE_BREAK) THEN DO;
1429	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1430	            PC = PC + 3;
1431	            /* Push (kind=BREAK, class_offset=V) onto pattern stack */
1432	            PSTK(PSTOP) = V;
1433	            PSTYP(PSTOP) = PK_BREAK;
1434	            PSTOP = PSTOP + 1;
1435	            LAST_PUSH_TYP = VTYP_PAT;
1436	        END;
1437	        ELSE IF (OP = OP_MAKE_REM) THEN DO;
1438	            PSTK(PSTOP) = 0;
1439	            PSTYP(PSTOP) = PK_REM;
1440	            PSTOP = PSTOP + 1;
1441	        END;
1442	        ELSE IF (OP = OP_MAKE_LIT_PAT) THEN DO;
1443	            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
1444	            PC = PC + 3;
1445	            PSTK(PSTOP) = V;
1446	            PSTYP(PSTOP) = PK_LIT;
1447	            PSTOP = PSTOP + 1;
1448	        END;
1449	        ELSE IF (OP = OP_PAT_CONCAT) THEN DO;
