1451	        END;
1452	        ELSE IF (OP = OP_PAT_CAP) THEN DO;
1453	            /* Mark previous pattern stack entry for capture */
1454	            IDX = AM_CODE(PC);
1455	            PC = PC + 1;
1456	            /* Store capture var index with the previous part */
1457	            IF (PSTOP > 0) THEN DO;
1458	                /* Use high bit trick: val = val | (capvar << 16) -- too complex.
