1460	                PSTK(PSTOP) = IDX;
1461	                PSTYP(PSTOP) = PK_CAP;
1462	                PSTOP = PSTOP + 1;
1463	            END;
1464	        END;
1465	        ELSE IF (OP = OP_PAT_MATCH2) THEN DO;
1466	            /* Execute compound pattern from pattern stack */
1467	            DCL SIDX2 INT;
1468	            DCL SUBJ_OFF2 INT;
1469	            DCL SUBJ_LEN2 INT;
1470	            DCL TRYPOS2 INT;
1471	            DCL MATCHED2 INT;
1472	            DCL CPOS INT;
1473	            DCL PI INT;
1474	            DCL PT INT;
1475	            DCL PV INT;
1476	            DCL MLEN2 INT;
1477	            DCL CAPVAR INT;
1478	            DCL CAPSTART INT;
1479	
1480	            SIDX2 = AM_CODE(PC);
1481	            PC = PC + 1;
1482	            SUBJ_OFF2 = VARS(SIDX2);
1483	            SUBJ_LEN2 = SLEN(ADDR(SB) + SUBJ_OFF2);
1484	
1485	            MATCHED2 = 0;
1486	            TRYPOS2 = 0;
1487	
1488	            /* Try at each starting position (unanchored) */
1489	            DO WHILE (TRYPOS2 <= SUBJ_LEN2 AND MATCHED2 = 0);
1490	                CPOS = TRYPOS2;
1491	                PI = 0;
1492	                MATCHED2 = 1;
1493	                CAPVAR = 0 - 1;
1494	
1495	                DO WHILE (PI < PSTOP AND MATCHED2 = 1);
1496	                    PT = PSTYP(PI);
1497	                    PV = PSTK(PI);
1498	
1499	                    IF (PT = PK_CAP) THEN DO;
1500	                        /* Capture: store current substring into capture var */
1501	                        IF (PV >= 0 AND PV < 16) THEN DO;
1502	                            DCL DST2 INT;
1503	                            DCL J INT;
1504	                            DCL SP3 PTR;
1505	                            DCL DP2 PTR;
1506	                            DST2 = SBPOS;
1507	                            J = CAPSTART;
1508	                            DO WHILE (J < CPOS);
1509	                                SP3 = ADDR(SB) + SUBJ_OFF2 + J;
1510	                                DP2 = ADDR(SB) + SBPOS;
1511	                                DP2->DTAG = SP3->DTAG;
1512	                                SBPOS = SBPOS + 1;
1513	                                J = J + 1;
1514	                            END;
1515	                            DP2 = ADDR(SB) + SBPOS;
1516	                            DP2->DTAG = 0;
1517	                            SBPOS = SBPOS + 1;
1518	                            VARS(PV) = DST2;
1519	                            VTYP(PV) = VTYP_STR;
1520	                        END;
1521	                    END;
1522	                    ELSE IF (PT = PK_SPAN) THEN DO;
1523	                        CAPSTART = CPOS;
1524	                        MLEN2 = EXEC_SPAN(ADDR(SB) + SUBJ_OFF2, SUBJ_LEN2, CPOS, ADDR(SB) + PV);
1525	                        IF (MLEN2 > 0) THEN
1526	                            CPOS = CPOS + MLEN2;
1527	                        ELSE
1528	                            MATCHED2 = 0;
1529	                    END;
1530	                    ELSE IF (PT = PK_BREAK) THEN DO;
1531	                        CAPSTART = CPOS;
1532	                        MLEN2 = EXEC_BREAK(ADDR(SB) + SUBJ_OFF2, SUBJ_LEN2, CPOS, ADDR(SB) + PV);
1533	                        IF (MLEN2 >= 0) THEN
1534	                            CPOS = CPOS + MLEN2;
1535	                        ELSE
1536	                            MATCHED2 = 0;
1537	                    END;
1538	                    ELSE IF (PT = PK_REM) THEN DO;
1539	                        CAPSTART = CPOS;
1540	                        CPOS = SUBJ_LEN2;
1541	                    END;
1542	                    ELSE IF (PT = PK_LIT) THEN DO;
1543	                        /* Literal match */
1544	                        DCL LLEN INT;
1545	                        DCL LK INT;
1546	                        DCL LP2 PTR;
1547	                        DCL CP2 PTR;
1548	                        LLEN = SLEN(ADDR(SB) + PV);
1549	                        IF (CPOS + LLEN > SUBJ_LEN2) THEN DO;
1550	                            MATCHED2 = 0;
1551	                        END;
1552	                        ELSE DO;
1553	                            LK = 0;
1554	                            DO WHILE (LK < LLEN);
1555	                                LP2 = ADDR(SB) + PV + LK;
1556	                                CP2 = ADDR(SB) + SUBJ_OFF2 + CPOS + LK;
1557	                                IF (LP2->DTAG != CP2->DTAG) THEN DO;
1558	                                    MATCHED2 = 0;
1559	                                    LK = LLEN;
1560	                                END;
1561	                                LK = LK + 1;
1562	                            END;
1563	                            IF (MATCHED2 = 1) THEN
1564	                                CPOS = CPOS + LLEN;
1565	                        END;
1566	                    END;
1567	
1568	                    PI = PI + 1;
1569	                END;
1570	
1571	                IF (MATCHED2 = 0) THEN
1572	                    TRYPOS2 = TRYPOS2 + 1;
1573	            END;
1574	
1575	            PSTOP = 0;
1576	            LAST_RESULT = MATCHED2;
1577	        END;
1578	        ELSE IF (OP = OP_MAKE_ARRAY) THEN DO;
1579	            /* Allocate array, push array ID */
1580	            V = ARR_CNT;
1581	            ARR_CNT = ARR_CNT + 1;
1582	            ESTK(ESP) = V;
1583	            ESP = ESP + 1;
1584	            LAST_PUSH_TYP = VTYP_ARR;
1585	        END;
1586	        ELSE IF (OP = OP_ARR_LOAD) THEN DO;
1587	            /* ARR_LOAD <arr_var>: load arr[idx] where idx is in next LOAD_VAR.
