1	/* sno_lex.plsw -- Layer 2: lexer, parser, symbol/label tables
2	 * Depends on: sno_util (L1)
3	/* */
4	%DEFINE LIBRARY;
5	%INCLUDE descr;
6	%INCLUDE heap;
7	%INCLUDE am;
8	%INCLUDE pat;
9	%INCLUDE snoglob;
10	
11	IS_A: PROC(C INT) RETURNS(INT);
12	    IF (C >= 65) THEN IF (C <= 90) THEN RETURN(1);
13	    IF (C >= 97) THEN IF (C <= 122) THEN RETURN(1);
14	    RETURN(0);
15	END;
16	
17	IS_D: PROC(C INT) RETURNS(INT);
18	    IF (C >= 48) THEN IF (C <= 57) THEN RETURN(1);
19	    RETURN(0);
20	END;
21	
22	IS_AN: PROC(C INT) RETURNS(INT);
23	    IF (IS_A(C) != 0) THEN RETURN(1);
24	    IF (IS_D(C) != 0) THEN RETURN(1);
25	    RETURN(0);
26	END;
27	
28	LEX: PROC;
29	    DCL C INT;
30	    DCL I INT;
31	    DCL Q INT;
32	    C = SRC(SPOS);
33	    IF (AT_SOL = 1) THEN DO;
34	        AT_SOL = 0;
35	        IF (C != 32 AND C != 9 AND C != 10 AND C != 0) THEN
36	            LHAS_LBL = 1;
37	        ELSE
38	            LHAS_LBL = 0;
39	    END;
40	    DO WHILE (C = 32 OR C = 9);
41	        SPOS = SPOS + 1;
42	        C = SRC(SPOS);
43	    END;
44	    IF (C = 0) THEN DO; TT = TK_EOF; RETURN; END;
45	    IF (C = 10) THEN DO; SPOS = SPOS + 1; TT = TK_EOL; AT_SOL = 1; RETURN; END;
46	    IF (C = 61) THEN DO; SPOS = SPOS + 1; TT = TK_EQ; RETURN; END;
47	    IF (C = 46) THEN DO; SPOS = SPOS + 1; TT = TK_DOT; RETURN; END;
48	    IF (C = 40) THEN DO; SPOS = SPOS + 1; TT = TK_LPAREN; RETURN; END;
49	    IF (C = 41) THEN DO; SPOS = SPOS + 1; TT = TK_RPAREN; RETURN; END;
50	    IF (C = 58) THEN DO; SPOS = SPOS + 1; TT = TK_COLON; RETURN; END;
51	    IF (C = 43) THEN DO; SPOS = SPOS + 1; TT = TK_PLUS; RETURN; END;
52	    IF (C = 45) THEN DO; SPOS = SPOS + 1; TT = TK_MINUS; RETURN; END;
53	    IF (C = 42) THEN DO; SPOS = SPOS + 1; TT = TK_STAR; RETURN; END;
54	    IF (C = 60) THEN DO; SPOS = SPOS + 1; TT = TK_LT; RETURN; END;
55	    IF (C = 62) THEN DO; SPOS = SPOS + 1; TT = TK_GT; RETURN; END;
56	    IF (C = 39 OR C = 34) THEN DO;
57	        Q = C;
58	        SPOS = SPOS + 1;
59	        I = 0;
60	        C = SRC(SPOS);
61	        DO WHILE (C != Q AND C != 0 AND C != 10);
62	            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
63	            SPOS = SPOS + 1;
64	            C = SRC(SPOS);
65	        END;
66	        IF (C = Q) THEN SPOS = SPOS + 1;
67	        TB(I) = 0;
68	        TN = I;
69	        TT = TK_STR;
70	        RETURN;
71	    END;
72	    IF (IS_D(C) != 0) THEN DO;
73	        TV = 0;
74	        DO WHILE (IS_D(SRC(SPOS)) != 0);
75	            C = SRC(SPOS);
76	            SPOS = SPOS + 1;
77	            TV = TV * 10 + (C - 48);
78	        END;
79	        TT = TK_INT;
80	        RETURN;
81	    END;
82	    IF (IS_A(C) != 0) THEN DO;
83	        I = 0;
84	        DO WHILE (IS_AN(SRC(SPOS)) != 0);
85	            C = SRC(SPOS);
86	            SPOS = SPOS + 1;
87	            IF (C >= 97) THEN IF (C <= 122) THEN C = C - 32;
88	            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
89	        END;
90	        TB(I) = 0;
91	        TN = I;
92	        TT = TK_IDENT;
93	        RETURN;
94	    END;
95	    /* Skip comment lines (starting with *) */
96	    IF (C = 42) THEN DO;
97	        DO WHILE (C != 10 AND C != 0);
98	            SPOS = SPOS + 1;
99	            C = SRC(SPOS);
100	        END;
101	        IF (C = 10) THEN DO; SPOS = SPOS + 1; AT_SOL = 1; END;
102	        TT = TK_EOL;
103	        RETURN;
104	    END;
105	    SPOS = SPOS + 1;
106	    TT = TK_EOF;
107	END;
108	
109	/* ================================================================
110	/* ================================================================
111	 * Symbol + Label tables
112	/* ================================================================ */
113	
114	/* SYMN, SYMV, SYMC declared in snoglob.msw */
115	
116	SYM_FIND: PROC(NOFF INT) RETURNS(INT);
117	    DCL I INT;
118	    DCL NP PTR;
119	    I = 0;
120	    DO WHILE (I < SYMC);
121	        NP = ADDR(SYMN) + I * 8;
122	        IF (SCEQ(NP, ADDR(SB) + NOFF) != 0) THEN RETURN(I);
123	        I = I + 1;
124	    END;
125	    RETURN(0 - 1);
126	END;
127	
128	SYM_ADD: PROC(NOFF INT) RETURNS(INT);
129	    DCL IDX INT;
130	    DCL NP PTR;
131	    DCL SRP PTR;
132	    DCL I INT;
133	    DCL C INT;
134	    IF (SYMC >= SYMMAX) THEN RETURN(0 - 1);
135	    IDX = SYMC;
136	    NP = ADDR(SYMN) + IDX * 8;
137	    SRP = ADDR(SB) + NOFF;
138	    I = 0;
139	    C = 1;
140	    DO WHILE (C != 0 AND I < 7);
141	        DCL DP PTR;
142	        DCL RP PTR;
143	        RP = SRP + I;
144	        C = RP->DTAG;
145	        DP = NP + I;
146	        DP->DTAG = C;
147	        I = I + 1;
148	    END;
149	    DCL EP PTR;
150	    EP = NP + I;
151	    EP->DTAG = 0;
152	    SYMV(IDX) = 0;
153	    SYMC = SYMC + 1;
154	    RETURN(IDX);
155	END;
156	
157	SYM_LOOKUP: PROC(NOFF INT) RETURNS(INT);
158	    DCL IDX INT;
159	    IDX = SYM_FIND(NOFF);
160	    IF (IDX >= 0) THEN RETURN(IDX);
161	    RETURN(SYM_ADD(NOFF));
162	END;
163	
164	/* ================================================================
165	 * Label table
166	/* ================================================================ */
167	
168	%DEFINE LBLMAX 8;
169	
170	/* LBLN, LBLS, LBLC declared in snoglob.msw */
171	
172	LBL_ADD: PROC(NOFF INT, STNUM INT);
173	    DCL NP PTR;
174	    DCL SRP PTR;
175	    DCL I INT;
176	    DCL C INT;
177	    IF (LBLC >= LBLMAX) THEN RETURN;
178	    NP = ADDR(LBLN) + LBLC * 8;
179	    SRP = ADDR(SB) + NOFF;
180	    I = 0;
181	    C = 1;
182	    DO WHILE (C != 0 AND I < 7);
183	        DCL DP PTR;
184	        DCL RP PTR;
185	        RP = SRP + I;
186	        C = RP->DTAG;
187	        DP = NP + I;
188	        DP->DTAG = C;
189	        I = I + 1;
190	    END;
191	    DCL EP PTR;
192	    EP = NP + I;
193	    EP->DTAG = 0;
194	    LBLS(LBLC) = STNUM;
195	    LBLC = LBLC + 1;
196	END;
197	
198	LBL_FIND: PROC(NOFF INT) RETURNS(INT);
199	    DCL I INT;
200	    DCL NP PTR;
201	    I = 0;
202	    DO WHILE (I < LBLC);
203	        NP = ADDR(LBLN) + I * 8;
204	        IF (SCEQ(NP, ADDR(SB) + NOFF) != 0) THEN RETURN(LBLS(I));
205	        I = I + 1;
206	    END;
207	    RETURN(0 - 1);
208	END;
209	
210	/* ================================================================
211	 * Statement table (max 16)
212	/* ================================================================ */
213	
214	%DEFINE STMAX 16;
215	
216	/* S_TYP, S_SUBJ, S_SIDX, S_OETY, S_OEV1, S_OEOP, S_OEV2, S_GTYP, S_GLBL, S_SPTR, STCNT in snoglob.msw */
217	
218	/* Expression parts for concatenation: up to 4 parts per statement.
219	 * S_EPCNT(s) = number of parts (0 = use S_OETY/S_OEV1 as before).
220	/* EP_TYP(s*4+i) = part type (OE_INT, OE_STR, OE_IDENT).
221	 * EP_VAL(s*4+i) = part value (int, str offset, sym idx). */
222	/* S_EPCNT, EP_TYP, EP_VAL declared in snoglob.msw */
223	
224	/* Pattern parts for compound match statements.
225	 * PP_TYP: OE_IDENT=var, OE_STR=literal, OE_SPAN, OE_BREAK, OE_REM, OE_CAP.
226	/* PP_VAL: sym idx, str offset, or class offset.
227	 * PP_VAL2: for OE_CAP = capture var idx. */
228	%DEFINE OE_BREAK 6;
229	%DEFINE OE_REM 7;
230	%DEFINE OE_CAP 8;
231	%DEFINE OE_ARRAY 9;
232	%DEFINE OE_ARRREF 10;
233	/* S_PPCNT, PP_TYP, PP_VAL declared in snoglob.msw */
234	
235	/* ================================================================
236	 * Parser
237	/* ================================================================ */
238	
239	/* Parse function name and param from a "FNNAME(PARAM)" string in TB
240	 * Returns 0 on success. Registers entry in FN table with FN_ENTRY=-1. */
241	DEF_PARSE: PROC RETURNS(INT);
242	    DCL I INT;
243	    DCL J INT;
244	    DCL NOFF1 INT;
245	    DCL NOFF2 INT;
246	    DCL DP PTR;
247	    DCL C INT;
248	    DCL FNS INT;
249	    DCL PRS INT;
250	    IF (FN_CNT >= 4) THEN RETURN(0 - 1);
251	    /* Copy fn name into SB */
252	    NOFF1 = SBPOS;
253	    I = 0;
254	    C = TB(I);
255	    DO WHILE (C != 0 AND C != 40);
256	        DP = ADDR(SB) + SBPOS;
257	        DP->DTAG = C;
258	        SBPOS = SBPOS + 1;
259	        I = I + 1;
260	        C = TB(I);
261	    END;
262	    DP = ADDR(SB) + SBPOS;
263	    DP->DTAG = 0;
264	    SBPOS = SBPOS + 1;
265	    IF (C != 40) THEN RETURN(0 - 1);
266	    I = I + 1;
267	    /* Copy param name */
268	    NOFF2 = SBPOS;
269	    C = TB(I);
270	    DO WHILE (C != 0 AND C != 41);
271	        DP = ADDR(SB) + SBPOS;
272	        DP->DTAG = C;
273	        SBPOS = SBPOS + 1;
274	        I = I + 1;
275	        C = TB(I);
276	    END;
277	    DP = ADDR(SB) + SBPOS;
278	    DP->DTAG = 0;
279	    SBPOS = SBPOS + 1;
280	    FNS = SYM_LOOKUP(NOFF1);
281	    PRS = SYM_LOOKUP(NOFF2);
282	    FN_NAME(FN_CNT) = FNS;
283	    FN_NAMOFF(FN_CNT) = NOFF1;
284	    FN_PARAM(FN_CNT) = PRS;
285	    FN_ENTRY(FN_CNT) = 0 - 1;
286	    FN_CNT = FN_CNT + 1;
287	    RETURN(0);
288	END;
289	
290	FN_FIND: PROC(SIDX INT) RETURNS(INT);
291	    DCL I INT;
292	    I = 0;
293	    DO WHILE (I < FN_CNT);
294	        IF (FN_NAME(I) = SIDX) THEN RETURN(I);
295	        I = I + 1;
296	    END;
297	    RETURN(0 - 1);
298	END;
299	
300	PARSE: PROC;
301	    DCL S INT;
302	    DCL NOFF INT;
303	    STCNT = 0;
304	    SBPOS = 0;
305	    SYMC = 0;
306	    LBLC = 0;
307	    FN_CNT = 0;
308	    SPOS = 0;
309	    AT_SOL = 1;
310	    CALL LEX;
311	
312	    DO WHILE (TT != TK_EOF AND STCNT < STMAX);
313	        S = STCNT;
314	        S_TYP(S) = ST_EMPTY;
315	        S_SUBJ(S) = 0 - 1;
316	        S_OETY(S) = OE_NONE;
317	        S_OEV1(S) = 0;
318	        S_OEOP(S) = 0;
319	        S_OEV2(S) = 0;
320	        S_GTYP(S) = GT_NONE;
321	        S_GLBL(S) = 0 - 1;
322	        S_SPTR(S) = 0 - 1;
323	        S_EPCNT(S) = 0;
324	        S_PPCNT(S) = 0;
325	        S_SIDX(S) = 0 - 1;
326	
327	        IF (TT = TK_EOL) THEN DO;
328	            CALL LEX;
329	            STCNT = STCNT + 1;
330	        END;
331	        ELSE IF (TT = TK_IDENT AND IS_END() != 0) THEN DO;
332	            S_TYP(S) = ST_END;
333	            NOFF = SBSAVE();
334	            CALL LBL_ADD(NOFF, S);
335	            CALL LEX;
336	            IF (TT = TK_EOL) THEN CALL LEX;
337	            STCNT = STCNT + 1;
338	        END;
339	        ELSE IF (TT = TK_IDENT) THEN DO;
340	            IF (LHAS_LBL = 1) THEN DO;
341	                NOFF = SBSAVE();
342	                CALL LBL_ADD(NOFF, S);
343	                CALL LEX;
344	            END;
345	
346	            IF (TT = TK_IDENT) THEN DO;
347	                NOFF = SBSAVE();
348	                S_SUBJ(S) = SYM_LOOKUP(NOFF);
349	                CALL LEX;
350	                /* Check for <index> (array element access) */
351	                IF (TT = TK_LT) THEN DO;
352	                    CALL LEX;
353	                    IF (TT = TK_IDENT) THEN DO;
354	                        NOFF = SBSAVE();
355	                        S_SIDX(S) = SYM_LOOKUP(NOFF);
356	                        CALL LEX;
357	                    END;
358	                    ELSE IF (TT = TK_INT) THEN DO;
359	                        /* Literal index -- store as negative (flag) */
360	                        S_SIDX(S) = 0 - TV - 1;
361	                        CALL LEX;
362	                    END;
363	                    IF (TT = TK_GT) THEN CALL LEX;
364	                END;
365	            END;
366	
367	            /* DEFINE('FNNAME(PARAM)') statement */
368	            IF (S_SUBJ(S) >= 0 AND TT = TK_LPAREN) THEN DO;
369	                DCL NP2 PTR;
370	                NP2 = ADDR(SYMN) + S_SUBJ(S) * 8;
371	                IF (NP2->DTAG = 68) THEN DO;
372	                    DCL NP3 PTR;
373	                    NP3 = NP2 + 1;
374	                    IF (NP3->DTAG = 69) THEN DO;
375	                        /* "DE..." -- assume DEFINE */
376	                        CALL LEX;  /* past ( */
377	                        IF (TT = TK_STR) THEN DO;
378	                            DCL DR INT;
379	                            DR = DEF_PARSE();
380	                            CALL LEX;
381	                        END;
382	                        IF (TT = TK_RPAREN) THEN CALL LEX;
383	                        S_TYP(S) = ST_EMPTY;
384	                        S_SUBJ(S) = 0 - 1;
385	                    END;
386	                END;
387	            END;
388	
389	            /* Check: is this a pattern match? (SUBJ parts... :goto)
390	             * If next token is IDENT (not =) or STR, it's a match stmt */
391	            IF ((TT = TK_IDENT OR TT = TK_STR) AND S_SUBJ(S) >= 0) THEN DO;
392	                DCL PPB INT;
393	                DCL PPI INT;
394	                S_TYP(S) = ST_MATCH;
395	                PPB = S * 8;
396	                PPI = 0;
397	
398	                /* Collect pattern parts until : or EOL */
399	                DO WHILE (TT != TK_COLON AND TT != TK_EOL AND TT != TK_EOF AND PPI < 8);
400	                    IF (TT = TK_DOT) THEN DO;
401	                        /* . CAPTURE */
402	                        CALL LEX;
403	                        IF (TT = TK_IDENT) THEN DO;
404	                            NOFF = SBSAVE();
405	                            PP_TYP(PPB + PPI) = OE_CAP;
406	                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
407	                            PPI = PPI + 1;
408	                            CALL LEX;
409	                        END;
410	                    END;
411	                    ELSE IF (TT = TK_STR) THEN DO;
412	                        PP_TYP(PPB + PPI) = OE_STR;
413	                        PP_VAL(PPB + PPI) = SBSAVE();
414	                        PPI = PPI + 1;
415	                        CALL LEX;
416	                    END;
417	                    ELSE IF (TT = TK_IDENT) THEN DO;
418	                        NOFF = SBSAVE();
419	                        /* Check for SPAN/BREAK/REM function */
420	                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
421	                            CALL LEX;
422	                            IF (TT = TK_LPAREN) THEN DO;
423	                                CALL LEX;
424	                                IF (TT = TK_STR) THEN DO;
425	                                    PP_TYP(PPB + PPI) = OE_SPAN;
426	                                    PP_VAL(PPB + PPI) = SBSAVE();
427	                                    PPI = PPI + 1;
428	                                    CALL LEX;
429	                                END;
430	                                IF (TT = TK_RPAREN) THEN CALL LEX;
431	                            END;
432	                        END;
433	                        ELSE IF (TB(0) = 66 AND TB(1) = 82 AND TB(2) = 69 AND TB(3) = 65 AND TB(4) = 75 AND TB(5) = 0) THEN DO;
434	                            CALL LEX;
435	                            IF (TT = TK_LPAREN) THEN DO;
436	                                CALL LEX;
437	                                IF (TT = TK_STR) THEN DO;
438	                                    PP_TYP(PPB + PPI) = OE_BREAK;
439	                                    PP_VAL(PPB + PPI) = SBSAVE();
440	                                    PPI = PPI + 1;
441	                                    CALL LEX;
442	                                END;
443	                                IF (TT = TK_RPAREN) THEN CALL LEX;
444	                            END;
445	                        END;
446	                        ELSE IF (TB(0) = 82 AND TB(1) = 69 AND TB(2) = 77 AND TB(3) = 0) THEN DO;
447	                            PP_TYP(PPB + PPI) = OE_REM;
448	                            PP_VAL(PPB + PPI) = 0;
449	                            PPI = PPI + 1;
450	                            CALL LEX;
451	                        END;
452	                        ELSE DO;
453	                            /* Pattern variable reference */
454	                            PP_TYP(PPB + PPI) = OE_IDENT;
455	                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
456	                            PPI = PPI + 1;
457	                            CALL LEX;
458	                        END;
459	                    END;
460	                    ELSE DO;
461	                        CALL LEX;
462	                    END;
463	                END;
464	
465	                S_PPCNT(S) = PPI;
466	            END;
467	            ELSE IF (TT = TK_EQ) THEN DO;
468	                DCL EPI INT;
469	                DCL EPB INT;
470	                S_TYP(S) = ST_ASSIGN;
471	                CALL LEX;
472	                EPB = S * 4;
473	                EPI = 0;
474	
475	                /* Collect expression parts */
476	                DO WHILE (TT = TK_INT OR TT = TK_STR OR TT = TK_IDENT);
477	                    IF (TT = TK_INT) THEN DO;
478	                        IF (EPI < 4) THEN DO;
479	                            EP_TYP(EPB + EPI) = OE_INT;
480	                            EP_VAL(EPB + EPI) = TV;
481	                            EPI = EPI + 1;
482	                        END;
483	                        CALL LEX;
484	                    END;
485	                    ELSE IF (TT = TK_STR) THEN DO;
486	                        IF (EPI < 4) THEN DO;
487	                            EP_TYP(EPB + EPI) = OE_STR;
488	                            EP_VAL(EPB + EPI) = SBSAVE();
489	                            EPI = EPI + 1;
490	                        END;
491	                        CALL LEX;
492	                    END;
493	                    ELSE IF (TT = TK_IDENT) THEN DO;
494	                        NOFF = SBSAVE();
495	                        /* Check for SPAN/ARRAY(...) */
496	                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
497	                            CALL LEX;
498	                            IF (TT = TK_LPAREN) THEN DO;
499	                                CALL LEX;
500	                                IF (TT = TK_STR) THEN DO;
501	                                    IF (EPI < 4) THEN DO;
502	                                        EP_TYP(EPB + EPI) = OE_SPAN;
503	                                        EP_VAL(EPB + EPI) = SBSAVE();
504	                                        EPI = EPI + 1;
505	                                    END;
506	                                    CALL LEX;
507	                                END;
508	                                IF (TT = TK_RPAREN) THEN CALL LEX;
509	                            END;
510	                        END;
511	                        ELSE IF (TB(0) = 65 AND TB(1) = 82 AND TB(2) = 82 AND TB(3) = 65 AND TB(4) = 89 AND TB(5) = 0) THEN DO;
512	                            /* ARRAY('1:50') */
513	                            CALL LEX;
514	                            IF (TT = TK_LPAREN) THEN DO;
515	                                CALL LEX;
516	                                IF (TT = TK_STR) THEN CALL LEX;
517	                                IF (TT = TK_RPAREN) THEN CALL LEX;
518	                            END;
519	                            IF (EPI < 4) THEN DO;
520	                                EP_TYP(EPB + EPI) = OE_ARRAY;
521	                                EP_VAL(EPB + EPI) = 0;
522	                                EPI = EPI + 1;
523	                            END;
524	                        END;
525	                        ELSE DO;
526	                            DCL SYMIDX INT;
527	                            DCL FNIDX INT;
528	                            SYMIDX = SYM_LOOKUP(NOFF);
529	                            CALL LEX;
530	                            FNIDX = 0 - 1;
531	                            IF (TT = TK_LPAREN) THEN
532	                                FNIDX = FN_FIND(SYMIDX);
533	                            /* Function call: NAME(ARG) */
534	                            IF (FNIDX >= 0) THEN DO;
535	                                IF (1 = 1) THEN DO;
536	                                    CALL LEX;  /* past ( */
537	                                    IF (EPI < 4) THEN DO;
538	                                        EP_TYP(EPB + EPI) = OE_FNCALL;
539	                                        EP_VAL(EPB + EPI) = FNIDX;
540	                                        EPI = EPI + 1;
541	                                    END;
542	                                    /* Single arg: IDENT or INT */
543	                                    IF (TT = TK_IDENT) THEN DO;
544	                                        DCL ANO INT;
545	                                        ANO = SBSAVE();
546	                                        IF (EPI < 4) THEN DO;
547	                                            EP_TYP(EPB + EPI) = OE_IDENT;
548	                                            EP_VAL(EPB + EPI) = SYM_LOOKUP(ANO);
549	                                            EPI = EPI + 1;
550	                                        END;
551	                                        CALL LEX;
552	                                    END;
553	                                    ELSE IF (TT = TK_INT) THEN DO;
554	                                        IF (EPI < 4) THEN DO;
555	                                            EP_TYP(EPB + EPI) = OE_INT;
556	                                            EP_VAL(EPB + EPI) = TV;
557	                                            EPI = EPI + 1;
558	                                        END;
559	                                        CALL LEX;
560	                                    END;
561	                                    IF (TT = TK_RPAREN) THEN CALL LEX;
562	                                END;
563	                            END;
564	                            /* Check for <index> (array ref in expr) */
565	                            ELSE IF (TT = TK_LT) THEN DO;
566	                                CALL LEX;
567	                                IF (EPI < 4) THEN DO;
568	                                    EP_TYP(EPB + EPI) = OE_ARRREF;
569	                                    EP_VAL(EPB + EPI) = SYMIDX;
570	                                    EPI = EPI + 1;
571	                                END;
572	                                /* Index: ident or int */
573	                                IF (TT = TK_IDENT) THEN DO;
574	                                    NOFF = SBSAVE();
575	                                    IF (EPI < 4) THEN DO;
576	                                        EP_TYP(EPB + EPI) = OE_IDENT;
577	                                        EP_VAL(EPB + EPI) = SYM_LOOKUP(NOFF);
578	                                        EPI = EPI + 1;
579	                                    END;
580	                                    CALL LEX;
581	                                END;
582	                                ELSE IF (TT = TK_INT) THEN DO;
583	                                    IF (EPI < 4) THEN DO;
584	                                        EP_TYP(EPB + EPI) = OE_INT;
585	                                        EP_VAL(EPB + EPI) = TV;
586	                                        EPI = EPI + 1;
587	                                    END;
588	                                    CALL LEX;
589	                                END;
590	                                IF (TT = TK_GT) THEN CALL LEX;
591	                            END;
592	                            ELSE DO;
593	                                IF (EPI < 4) THEN DO;
594	                                    EP_TYP(EPB + EPI) = OE_IDENT;
595	                                    EP_VAL(EPB + EPI) = SYMIDX;
596	                                    EPI = EPI + 1;
597	                                END;
598	                            END;
599	                        END;
600	                    END;
601	
602	                    /* Check for binary operator */
603	                    IF (TT = TK_PLUS OR TT = TK_MINUS OR TT = TK_STAR) THEN DO;
604	                        /* Store op, then parse second operand on next loop */
605	                        S_OEOP(S) = TT;
606	                        CALL LEX;
607	                    END;
608	                END;
609	
610	                S_EPCNT(S) = EPI;
611	                /* For backward compat: if 1 part, set S_OETY/S_OEV1 */
612	                IF (EPI = 1) THEN DO;
613	                    S_OETY(S) = EP_TYP(EPB);
614	                    S_OEV1(S) = EP_VAL(EPB);
615	                    IF (S_OETY(S) = OE_STR OR S_OETY(S) = OE_SPAN) THEN
616	                        S_SPTR(S) = EP_VAL(EPB);
617	                END;
618	                ELSE IF (EPI = 2 AND S_OEOP(S) != 0) THEN DO;
619	                    /* Binary op: part0 OP part1 */
620	                    S_OETY(S) = OE_BINOP;
621	                    S_OEV1(S) = EP_VAL(EPB);
622	                    S_OEV2(S) = EP_VAL(EPB + 1);
623	                END;
624	                ELSE IF (EPI >= 2) THEN DO;
625	                    /* Concatenation */
626	                    S_OETY(S) = OE_NONE;
627	                END;
628	            END;
629	
630	            IF (TT = TK_COLON) THEN DO;
631	                CALL LEX;
632	                IF (TT = TK_IDENT) THEN DO;
633	                    IF (TB(0) = 83 AND TB(1) = 0) THEN DO;
634	                        S_GTYP(S) = GT_SUCC;
635	                        CALL LEX;
636	                    END;
637	                    ELSE IF (TB(0) = 70 AND TB(1) = 0) THEN DO;
638	                        S_GTYP(S) = GT_FAIL;
639	                        CALL LEX;
640	                    END;
641	                END;
642	                ELSE IF (TT = TK_LPAREN) THEN DO;
643	                    S_GTYP(S) = GT_UNCOND;
644	                END;
645	                IF (TT = TK_LPAREN) THEN DO;
646	                    CALL LEX;
647	                    IF (TT = TK_IDENT) THEN DO;
648	                        /* Detect :(RETURN) and :(FRETURN) */
649	                        IF (TB(0) = 82 AND TB(1) = 69 AND TB(2) = 84 AND TB(3) = 85 AND TB(4) = 82 AND TB(5) = 78 AND TB(6) = 0) THEN DO;
650	                            S_GTYP(S) = GT_RET;
651	                            S_GLBL(S) = 0 - 1;
652	                            CALL LEX;
653	                        END;
654	                        ELSE IF (TB(0) = 70 AND TB(1) = 82 AND TB(2) = 69 AND TB(3) = 84 AND TB(4) = 85 AND TB(5) = 82 AND TB(6) = 78 AND TB(7) = 0) THEN DO;
655	                            S_GTYP(S) = GT_FRET;
656	                            S_GLBL(S) = 0 - 1;
657	                            CALL LEX;
658	                        END;
659	                        ELSE DO;
660	                            S_GLBL(S) = SBSAVE();
661	                            CALL LEX;
662	                        END;
663	                    END;
664	                    IF (TT = TK_RPAREN) THEN CALL LEX;
665	                END;
666	            END;
667	
668	            DO WHILE (TT != TK_EOL AND TT != TK_EOF);
669	                CALL LEX;
670	            END;
671	            IF (TT = TK_EOL) THEN CALL LEX;
672	            STCNT = STCNT + 1;
673	        END;
674	        ELSE DO;
675	            CALL LEX;
676	        END;
677	    END;
678	
679	    /* Resolve FN_ENTRY via label lookup */
680	    DCL FI INT;
681	    FI = 0;
682	    DO WHILE (FI < FN_CNT);
683	        FN_ENTRY(FI) = LBL_FIND(FN_NAMOFF(FI));
684	        FI = FI + 1;
685	    END;
686	END;
687	
688	/* ================================================================
689	 * AM code buffer + emitter
690	/* ================================================================ */
691	
692	/* AM_CODE, AM_PC, STMT_ADDR declared in snoglob.msw */
693	
694	/* Dummy MAIN for library compilation */
695	MAIN: PROC;
696	END;
