/* sno_lex.plsw -- Layer 2: lexer, parser, symbol/label tables
 * Depends on: sno_util (L1)
/* */
%DEFINE LIBRARY;
%INCLUDE descr;
%INCLUDE heap;
%INCLUDE am;
%INCLUDE pat;
%INCLUDE snoglob;

IS_A: PROC(C INT) RETURNS(INT);
    IF (C >= 65) THEN IF (C <= 90) THEN RETURN(1);
    IF (C >= 97) THEN IF (C <= 122) THEN RETURN(1);
    RETURN(0);
END;

IS_D: PROC(C INT) RETURNS(INT);
    IF (C >= 48) THEN IF (C <= 57) THEN RETURN(1);
    RETURN(0);
END;

IS_AN: PROC(C INT) RETURNS(INT);
    IF (IS_A(C) != 0) THEN RETURN(1);
    IF (IS_D(C) != 0) THEN RETURN(1);
    RETURN(0);
END;

LEX: PROC;
    DCL C INT;
    DCL I INT;
    DCL Q INT;
    C = SRC(SPOS);
    IF (AT_SOL = 1) THEN DO;
        AT_SOL = 0;
        IF (C != 32 AND C != 9 AND C != 10 AND C != 0) THEN
            LHAS_LBL = 1;
        ELSE
            LHAS_LBL = 0;
    END;
    DO WHILE (C = 32 OR C = 9);
        SPOS = SPOS + 1;
        C = SRC(SPOS);
    END;
    IF (C = 0) THEN DO; TT = TK_EOF; RETURN; END;
    IF (C = 10) THEN DO; SPOS = SPOS + 1; TT = TK_EOL; AT_SOL = 1; RETURN; END;
    IF (C = 61) THEN DO; SPOS = SPOS + 1; TT = TK_EQ; RETURN; END;
    IF (C = 46) THEN DO; SPOS = SPOS + 1; TT = TK_DOT; RETURN; END;
    IF (C = 40) THEN DO; SPOS = SPOS + 1; TT = TK_LPAREN; RETURN; END;
    IF (C = 41) THEN DO; SPOS = SPOS + 1; TT = TK_RPAREN; RETURN; END;
    IF (C = 58) THEN DO; SPOS = SPOS + 1; TT = TK_COLON; RETURN; END;
    IF (C = 43) THEN DO; SPOS = SPOS + 1; TT = TK_PLUS; RETURN; END;
    IF (C = 45) THEN DO; SPOS = SPOS + 1; TT = TK_MINUS; RETURN; END;
    IF (C = 42) THEN DO; SPOS = SPOS + 1; TT = TK_STAR; RETURN; END;
    IF (C = 60) THEN DO; SPOS = SPOS + 1; TT = TK_LT; RETURN; END;
    IF (C = 62) THEN DO; SPOS = SPOS + 1; TT = TK_GT; RETURN; END;
    IF (C = 39 OR C = 34) THEN DO;
        Q = C;
        SPOS = SPOS + 1;
        I = 0;
        C = SRC(SPOS);
        DO WHILE (C != Q AND C != 0 AND C != 10);
            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
            SPOS = SPOS + 1;
            C = SRC(SPOS);
        END;
        IF (C = Q) THEN SPOS = SPOS + 1;
        TB(I) = 0;
        TN = I;
        TT = TK_STR;
        RETURN;
    END;
    IF (IS_D(C) != 0) THEN DO;
        TV = 0;
        DO WHILE (IS_D(SRC(SPOS)) != 0);
            C = SRC(SPOS);
            SPOS = SPOS + 1;
            TV = TV * 10 + (C - 48);
        END;
        TT = TK_INT;
        RETURN;
    END;
    IF (IS_A(C) != 0) THEN DO;
        I = 0;
        DO WHILE (IS_AN(SRC(SPOS)) != 0);
            C = SRC(SPOS);
            SPOS = SPOS + 1;
            IF (C >= 97) THEN IF (C <= 122) THEN C = C - 32;
            IF (I < 31) THEN DO; TB(I) = C; I = I + 1; END;
        END;
        TB(I) = 0;
        TN = I;
        TT = TK_IDENT;
        RETURN;
    END;
    /* Skip comment lines (starting with *) */
    IF (C = 42) THEN DO;
        DO WHILE (C != 10 AND C != 0);
            SPOS = SPOS + 1;
            C = SRC(SPOS);
        END;
        IF (C = 10) THEN DO; SPOS = SPOS + 1; AT_SOL = 1; END;
        TT = TK_EOL;
        RETURN;
    END;
    SPOS = SPOS + 1;
    TT = TK_EOF;
END;

/* ================================================================
/* ================================================================
 * Symbol + Label tables
/* ================================================================ */

/* SYMN, SYMV, SYMC declared in snoglob.msw */

SYM_FIND: PROC(NOFF INT) RETURNS(INT);
    DCL I INT;
    DCL NP PTR;
    I = 0;
    DO WHILE (I < SYMC);
        NP = ADDR(SYMN) + I * 8;
        IF (SCEQ(NP, ADDR(SB) + NOFF) != 0) THEN RETURN(I);
        I = I + 1;
    END;
    RETURN(0 - 1);
END;

SYM_ADD: PROC(NOFF INT) RETURNS(INT);
    DCL IDX INT;
    DCL NP PTR;
    DCL SRP PTR;
    DCL I INT;
    DCL C INT;
    IF (SYMC >= SYMMAX) THEN RETURN(0 - 1);
    IDX = SYMC;
    NP = ADDR(SYMN) + IDX * 8;
    SRP = ADDR(SB) + NOFF;
    I = 0;
    C = 1;
    DO WHILE (C != 0 AND I < 7);
        DCL DP PTR;
        DCL RP PTR;
        RP = SRP + I;
        C = RP->DTAG;
        DP = NP + I;
        DP->DTAG = C;
        I = I + 1;
    END;
    DCL EP PTR;
    EP = NP + I;
    EP->DTAG = 0;
    SYMV(IDX) = 0;
    SYMC = SYMC + 1;
    RETURN(IDX);
END;

SYM_LOOKUP: PROC(NOFF INT) RETURNS(INT);
    DCL IDX INT;
    IDX = SYM_FIND(NOFF);
    IF (IDX >= 0) THEN RETURN(IDX);
    RETURN(SYM_ADD(NOFF));
END;

/* ================================================================
 * Label table
/* ================================================================ */

%DEFINE LBLMAX 8;

/* LBLN, LBLS, LBLC declared in snoglob.msw */

LBL_ADD: PROC(NOFF INT, STNUM INT);
    DCL NP PTR;
    DCL SRP PTR;
    DCL I INT;
    DCL C INT;
    IF (LBLC >= LBLMAX) THEN RETURN;
    NP = ADDR(LBLN) + LBLC * 8;
    SRP = ADDR(SB) + NOFF;
    I = 0;
    C = 1;
    DO WHILE (C != 0 AND I < 7);
        DCL DP PTR;
        DCL RP PTR;
        RP = SRP + I;
        C = RP->DTAG;
        DP = NP + I;
        DP->DTAG = C;
        I = I + 1;
    END;
    DCL EP PTR;
    EP = NP + I;
    EP->DTAG = 0;
    LBLS(LBLC) = STNUM;
    LBLC = LBLC + 1;
END;

LBL_FIND: PROC(NOFF INT) RETURNS(INT);
    DCL I INT;
    DCL NP PTR;
    I = 0;
    DO WHILE (I < LBLC);
        NP = ADDR(LBLN) + I * 8;
        IF (SCEQ(NP, ADDR(SB) + NOFF) != 0) THEN RETURN(LBLS(I));
        I = I + 1;
    END;
    RETURN(0 - 1);
END;

/* ================================================================
 * Statement table (max 16)
/* ================================================================ */

%DEFINE STMAX 16;

/* S_TYP, S_SUBJ, S_SIDX, S_OETY, S_OEV1, S_OEOP, S_OEV2, S_GTYP, S_GLBL, S_SPTR, STCNT in snoglob.msw */

/* Expression parts for concatenation: up to 4 parts per statement.
 * S_EPCNT(s) = number of parts (0 = use S_OETY/S_OEV1 as before).
/* EP_TYP(s*4+i) = part type (OE_INT, OE_STR, OE_IDENT).
 * EP_VAL(s*4+i) = part value (int, str offset, sym idx). */
/* S_EPCNT, EP_TYP, EP_VAL declared in snoglob.msw */

/* Pattern parts for compound match statements.
 * PP_TYP: OE_IDENT=var, OE_STR=literal, OE_SPAN, OE_BREAK, OE_REM, OE_CAP.
/* PP_VAL: sym idx, str offset, or class offset.
 * PP_VAL2: for OE_CAP = capture var idx. */
%DEFINE OE_BREAK 6;
%DEFINE OE_REM 7;
%DEFINE OE_CAP 8;
%DEFINE OE_ARRAY 9;
%DEFINE OE_ARRREF 10;
/* S_PPCNT, PP_TYP, PP_VAL declared in snoglob.msw */

/* ================================================================
 * Parser
/* ================================================================ */

/* Parse function name and param from a "FNNAME(PARAM)" string in TB
 * Returns 0 on success. Registers entry in FN table with FN_ENTRY=-1. */
DEF_PARSE: PROC RETURNS(INT);
    DCL I INT;
    DCL J INT;
    DCL NOFF1 INT;
    DCL NOFF2 INT;
    DCL DP PTR;
    DCL C INT;
    DCL FNS INT;
    DCL PRS INT;
    IF (FN_CNT >= 4) THEN RETURN(0 - 1);
    /* Copy fn name into SB */
    NOFF1 = SBPOS;
    I = 0;
    C = TB(I);
    DO WHILE (C != 0 AND C != 40);
        DP = ADDR(SB) + SBPOS;
        DP->DTAG = C;
        SBPOS = SBPOS + 1;
        I = I + 1;
        C = TB(I);
    END;
    DP = ADDR(SB) + SBPOS;
    DP->DTAG = 0;
    SBPOS = SBPOS + 1;
    IF (C != 40) THEN RETURN(0 - 1);
    I = I + 1;
    /* Copy param name */
    NOFF2 = SBPOS;
    C = TB(I);
    DO WHILE (C != 0 AND C != 41);
        DP = ADDR(SB) + SBPOS;
        DP->DTAG = C;
        SBPOS = SBPOS + 1;
        I = I + 1;
        C = TB(I);
    END;
    DP = ADDR(SB) + SBPOS;
    DP->DTAG = 0;
    SBPOS = SBPOS + 1;
    FNS = SYM_LOOKUP(NOFF1);
    PRS = SYM_LOOKUP(NOFF2);
    FN_NAME(FN_CNT) = FNS;
    FN_NAMOFF(FN_CNT) = NOFF1;
    FN_PARAM(FN_CNT) = PRS;
    FN_ENTRY(FN_CNT) = 0 - 1;
    FN_CNT = FN_CNT + 1;
    RETURN(0);
END;

FN_FIND: PROC(SIDX INT) RETURNS(INT);
    DCL I INT;
    I = 0;
    DO WHILE (I < FN_CNT);
        IF (FN_NAME(I) = SIDX) THEN RETURN(I);
        I = I + 1;
    END;
    RETURN(0 - 1);
END;

PARSE: PROC;
    DCL S INT;
    DCL NOFF INT;
    STCNT = 0;
    SBPOS = 0;
    SYMC = 0;
    LBLC = 0;
    FN_CNT = 0;
    SPOS = 0;
    AT_SOL = 1;
    CALL LEX;

    DO WHILE (TT != TK_EOF AND STCNT < STMAX);
        S = STCNT;
        S_TYP(S) = ST_EMPTY;
        S_SUBJ(S) = 0 - 1;
        S_OETY(S) = OE_NONE;
        S_OEV1(S) = 0;
        S_OEOP(S) = 0;
        S_OEV2(S) = 0;
        S_GTYP(S) = GT_NONE;
        S_GLBL(S) = 0 - 1;
        S_SPTR(S) = 0 - 1;
        S_EPCNT(S) = 0;
        S_PPCNT(S) = 0;
        S_SIDX(S) = 0 - 1;

        IF (TT = TK_EOL) THEN DO;
            CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE IF (TT = TK_IDENT AND IS_END() != 0) THEN DO;
            S_TYP(S) = ST_END;
            NOFF = SBSAVE();
            CALL LBL_ADD(NOFF, S);
            CALL LEX;
            IF (TT = TK_EOL) THEN CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE IF (TT = TK_IDENT) THEN DO;
            IF (LHAS_LBL = 1) THEN DO;
                NOFF = SBSAVE();
                CALL LBL_ADD(NOFF, S);
                CALL LEX;
            END;

            IF (TT = TK_IDENT) THEN DO;
                NOFF = SBSAVE();
                S_SUBJ(S) = SYM_LOOKUP(NOFF);
                CALL LEX;
                /* Check for <index> (array element access) */
                IF (TT = TK_LT) THEN DO;
                    CALL LEX;
                    IF (TT = TK_IDENT) THEN DO;
                        NOFF = SBSAVE();
                        S_SIDX(S) = SYM_LOOKUP(NOFF);
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_INT) THEN DO;
                        /* Literal index -- store as negative (flag) */
                        S_SIDX(S) = 0 - TV - 1;
                        CALL LEX;
                    END;
                    IF (TT = TK_GT) THEN CALL LEX;
                END;
            END;

            /* DEFINE('FNNAME(PARAM)') statement */
            IF (S_SUBJ(S) >= 0 AND TT = TK_LPAREN) THEN DO;
                DCL NP2 PTR;
                NP2 = ADDR(SYMN) + S_SUBJ(S) * 8;
                IF (NP2->DTAG = 68) THEN DO;
                    DCL NP3 PTR;
                    NP3 = NP2 + 1;
                    IF (NP3->DTAG = 69) THEN DO;
                        /* "DE..." -- assume DEFINE */
                        CALL LEX;  /* past ( */
                        IF (TT = TK_STR) THEN DO;
                            DCL DR INT;
                            DR = DEF_PARSE();
                            CALL LEX;
                        END;
                        IF (TT = TK_RPAREN) THEN CALL LEX;
                        S_TYP(S) = ST_EMPTY;
                        S_SUBJ(S) = 0 - 1;
                    END;
                END;
            END;

            /* Check: is this a pattern match? (SUBJ parts... :goto)
             * If next token is IDENT (not =) or STR, it's a match stmt */
            IF ((TT = TK_IDENT OR TT = TK_STR) AND S_SUBJ(S) >= 0) THEN DO;
                DCL PPB INT;
                DCL PPI INT;
                S_TYP(S) = ST_MATCH;
                PPB = S * 8;
                PPI = 0;

                /* Collect pattern parts until : or EOL */
                DO WHILE (TT != TK_COLON AND TT != TK_EOL AND TT != TK_EOF AND PPI < 8);
                    IF (TT = TK_DOT) THEN DO;
                        /* . CAPTURE */
                        CALL LEX;
                        IF (TT = TK_IDENT) THEN DO;
                            NOFF = SBSAVE();
                            PP_TYP(PPB + PPI) = OE_CAP;
                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
                            PPI = PPI + 1;
                            CALL LEX;
                        END;
                    END;
                    ELSE IF (TT = TK_STR) THEN DO;
                        PP_TYP(PPB + PPI) = OE_STR;
                        PP_VAL(PPB + PPI) = SBSAVE();
                        PPI = PPI + 1;
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_IDENT) THEN DO;
                        NOFF = SBSAVE();
                        /* Check for SPAN/BREAK/REM function */
                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN DO;
                                    PP_TYP(PPB + PPI) = OE_SPAN;
                                    PP_VAL(PPB + PPI) = SBSAVE();
                                    PPI = PPI + 1;
                                    CALL LEX;
                                END;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                        END;
                        ELSE IF (TB(0) = 66 AND TB(1) = 82 AND TB(2) = 69 AND TB(3) = 65 AND TB(4) = 75 AND TB(5) = 0) THEN DO;
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN DO;
                                    PP_TYP(PPB + PPI) = OE_BREAK;
                                    PP_VAL(PPB + PPI) = SBSAVE();
                                    PPI = PPI + 1;
                                    CALL LEX;
                                END;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                        END;
                        ELSE IF (TB(0) = 82 AND TB(1) = 69 AND TB(2) = 77 AND TB(3) = 0) THEN DO;
                            PP_TYP(PPB + PPI) = OE_REM;
                            PP_VAL(PPB + PPI) = 0;
                            PPI = PPI + 1;
                            CALL LEX;
                        END;
                        ELSE DO;
                            /* Pattern variable reference */
                            PP_TYP(PPB + PPI) = OE_IDENT;
                            PP_VAL(PPB + PPI) = SYM_LOOKUP(NOFF);
                            PPI = PPI + 1;
                            CALL LEX;
                        END;
                    END;
                    ELSE DO;
                        CALL LEX;
                    END;
                END;

                S_PPCNT(S) = PPI;
            END;
            ELSE IF (TT = TK_EQ) THEN DO;
                DCL EPI INT;
                DCL EPB INT;
                S_TYP(S) = ST_ASSIGN;
                CALL LEX;
                EPB = S * 4;
                EPI = 0;

                /* Collect expression parts */
                DO WHILE (TT = TK_INT OR TT = TK_STR OR TT = TK_IDENT);
                    IF (TT = TK_INT) THEN DO;
                        IF (EPI < 4) THEN DO;
                            EP_TYP(EPB + EPI) = OE_INT;
                            EP_VAL(EPB + EPI) = TV;
                            EPI = EPI + 1;
                        END;
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_STR) THEN DO;
                        IF (EPI < 4) THEN DO;
                            EP_TYP(EPB + EPI) = OE_STR;
                            EP_VAL(EPB + EPI) = SBSAVE();
                            EPI = EPI + 1;
                        END;
                        CALL LEX;
                    END;
                    ELSE IF (TT = TK_IDENT) THEN DO;
                        NOFF = SBSAVE();
                        /* Check for SPAN/ARRAY(...) */
                        IF (TB(0) = 83 AND TB(1) = 80 AND TB(2) = 65 AND TB(3) = 78 AND TB(4) = 0) THEN DO;
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN DO;
                                    IF (EPI < 4) THEN DO;
                                        EP_TYP(EPB + EPI) = OE_SPAN;
                                        EP_VAL(EPB + EPI) = SBSAVE();
                                        EPI = EPI + 1;
                                    END;
                                    CALL LEX;
                                END;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                        END;
                        ELSE IF (TB(0) = 65 AND TB(1) = 82 AND TB(2) = 82 AND TB(3) = 65 AND TB(4) = 89 AND TB(5) = 0) THEN DO;
                            /* ARRAY('1:50') */
                            CALL LEX;
                            IF (TT = TK_LPAREN) THEN DO;
                                CALL LEX;
                                IF (TT = TK_STR) THEN CALL LEX;
                                IF (TT = TK_RPAREN) THEN CALL LEX;
                            END;
                            IF (EPI < 4) THEN DO;
                                EP_TYP(EPB + EPI) = OE_ARRAY;
                                EP_VAL(EPB + EPI) = 0;
                                EPI = EPI + 1;
                            END;
                        END;
                        ELSE DO;
                            DCL SYMIDX INT;
                            DCL FNIDX INT;
                            SYMIDX = SYM_LOOKUP(NOFF);
                            CALL LEX;
                            FNIDX = 0 - 1;
                            IF (TT = TK_LPAREN) THEN
                                FNIDX = FN_FIND(SYMIDX);
                            /* Function call: NAME(ARG) */
                            IF (FNIDX >= 0) THEN DO;
                                IF (1 = 1) THEN DO;
                                    CALL LEX;  /* past ( */
                                    IF (EPI < 4) THEN DO;
                                        EP_TYP(EPB + EPI) = OE_FNCALL;
                                        EP_VAL(EPB + EPI) = FNIDX;
                                        EPI = EPI + 1;
                                    END;
                                    /* Single arg: IDENT or INT */
                                    IF (TT = TK_IDENT) THEN DO;
                                        DCL ANO INT;
                                        ANO = SBSAVE();
                                        IF (EPI < 4) THEN DO;
                                            EP_TYP(EPB + EPI) = OE_IDENT;
                                            EP_VAL(EPB + EPI) = SYM_LOOKUP(ANO);
                                            EPI = EPI + 1;
                                        END;
                                        CALL LEX;
                                    END;
                                    ELSE IF (TT = TK_INT) THEN DO;
                                        IF (EPI < 4) THEN DO;
                                            EP_TYP(EPB + EPI) = OE_INT;
                                            EP_VAL(EPB + EPI) = TV;
                                            EPI = EPI + 1;
                                        END;
                                        CALL LEX;
                                    END;
                                    IF (TT = TK_RPAREN) THEN CALL LEX;
                                END;
                            END;
                            /* Check for <index> (array ref in expr) */
                            ELSE IF (TT = TK_LT) THEN DO;
                                CALL LEX;
                                IF (EPI < 4) THEN DO;
                                    EP_TYP(EPB + EPI) = OE_ARRREF;
                                    EP_VAL(EPB + EPI) = SYMIDX;
                                    EPI = EPI + 1;
                                END;
                                /* Index: ident or int */
                                IF (TT = TK_IDENT) THEN DO;
                                    NOFF = SBSAVE();
                                    IF (EPI < 4) THEN DO;
                                        EP_TYP(EPB + EPI) = OE_IDENT;
                                        EP_VAL(EPB + EPI) = SYM_LOOKUP(NOFF);
                                        EPI = EPI + 1;
                                    END;
                                    CALL LEX;
                                END;
                                ELSE IF (TT = TK_INT) THEN DO;
                                    IF (EPI < 4) THEN DO;
                                        EP_TYP(EPB + EPI) = OE_INT;
                                        EP_VAL(EPB + EPI) = TV;
                                        EPI = EPI + 1;
                                    END;
                                    CALL LEX;
                                END;
                                IF (TT = TK_GT) THEN CALL LEX;
                            END;
                            ELSE DO;
                                IF (EPI < 4) THEN DO;
                                    EP_TYP(EPB + EPI) = OE_IDENT;
                                    EP_VAL(EPB + EPI) = SYMIDX;
                                    EPI = EPI + 1;
                                END;
                            END;
                        END;
                    END;

                    /* Check for binary operator */
                    IF (TT = TK_PLUS OR TT = TK_MINUS OR TT = TK_STAR) THEN DO;
                        /* Store op, then parse second operand on next loop */
                        S_OEOP(S) = TT;
                        CALL LEX;
                    END;
                END;

                S_EPCNT(S) = EPI;
                /* For backward compat: if 1 part, set S_OETY/S_OEV1 */
                IF (EPI = 1) THEN DO;
                    S_OETY(S) = EP_TYP(EPB);
                    S_OEV1(S) = EP_VAL(EPB);
                    IF (S_OETY(S) = OE_STR OR S_OETY(S) = OE_SPAN) THEN
                        S_SPTR(S) = EP_VAL(EPB);
                END;
                ELSE IF (EPI = 2 AND S_OEOP(S) != 0) THEN DO;
                    /* Binary op: part0 OP part1 */
                    S_OETY(S) = OE_BINOP;
                    S_OEV1(S) = EP_VAL(EPB);
                    S_OEV2(S) = EP_VAL(EPB + 1);
                END;
                ELSE IF (EPI >= 2) THEN DO;
                    /* Concatenation */
                    S_OETY(S) = OE_NONE;
                END;
            END;

            IF (TT = TK_COLON) THEN DO;
                CALL LEX;
                IF (TT = TK_IDENT) THEN DO;
                    IF (TB(0) = 83 AND TB(1) = 0) THEN DO;
                        S_GTYP(S) = GT_SUCC;
                        CALL LEX;
                    END;
                    ELSE IF (TB(0) = 70 AND TB(1) = 0) THEN DO;
                        S_GTYP(S) = GT_FAIL;
                        CALL LEX;
                    END;
                END;
                ELSE IF (TT = TK_LPAREN) THEN DO;
                    S_GTYP(S) = GT_UNCOND;
                END;
                IF (TT = TK_LPAREN) THEN DO;
                    CALL LEX;
                    IF (TT = TK_IDENT) THEN DO;
                        /* Detect :(RETURN) and :(FRETURN) */
                        IF (TB(0) = 82 AND TB(1) = 69 AND TB(2) = 84 AND TB(3) = 85 AND TB(4) = 82 AND TB(5) = 78 AND TB(6) = 0) THEN DO;
                            S_GTYP(S) = GT_RET;
                            S_GLBL(S) = 0 - 1;
                            CALL LEX;
                        END;
                        ELSE IF (TB(0) = 70 AND TB(1) = 82 AND TB(2) = 69 AND TB(3) = 84 AND TB(4) = 85 AND TB(5) = 82 AND TB(6) = 78 AND TB(7) = 0) THEN DO;
                            S_GTYP(S) = GT_FRET;
                            S_GLBL(S) = 0 - 1;
                            CALL LEX;
                        END;
                        ELSE DO;
                            S_GLBL(S) = SBSAVE();
                            CALL LEX;
                        END;
                    END;
                    IF (TT = TK_RPAREN) THEN CALL LEX;
                END;
            END;

            DO WHILE (TT != TK_EOL AND TT != TK_EOF);
                CALL LEX;
            END;
            IF (TT = TK_EOL) THEN CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE DO;
            CALL LEX;
        END;
    END;

    /* Resolve FN_ENTRY via label lookup */
    DCL FI INT;
    FI = 0;
    DO WHILE (FI < FN_CNT);
        FN_ENTRY(FI) = LBL_FIND(FN_NAMOFF(FI));
        FI = FI + 1;
    END;
END;

/* ================================================================
 * AM code buffer + emitter
/* ================================================================ */

/* AM_CODE, AM_PC, STMT_ADDR declared in snoglob.msw */

/* Dummy MAIN for library compilation */
MAIN: PROC;
END;

content.content:
1	/* sno_exec.plsw -- Layer 3: AM emitter, lowering, executor, patterns
2	 * Depends on: sno_util (L1), sno_lex (L2)
3	/* */
4	%DEFINE LIBRARY;
5	%INCLUDE descr;
6	%INCLUDE heap;
7	%INCLUDE am;
8	%INCLUDE pat;
9	%INCLUDE snoglob;
10	
11	AM_INIT: PROC;
12	    AM_PC = 0;
13	END;
14	
15	AM_EMIT_OP: PROC(OP INT);
16	    AM_CODE(AM_PC) = OP;
17	    AM_PC = AM_PC + 1;
18	END;
19	
20	AM_EMIT_BYTE: PROC(V INT);
21	    AM_CODE(AM_PC) = V;
22	    AM_PC = AM_PC + 1;
23	END;
24	
25	AM_EMIT_WORD: PROC(V INT);
26	    DCL B0 INT;
27	    DCL B1 INT;
28	    DCL B2 INT;
29	    DCL REM INT;
30	    REM = V;
31	    B2 = 0;
32	    DO WHILE (REM > 65535);
33	        REM = REM - 65536;
34	        B2 = B2 + 1;
35	    END;
36	    B1 = 0;
37	    DO WHILE (REM > 255);
38	        REM = REM - 256;
39	        B1 = B1 + 1;
40	    END;
41	    B0 = REM;
42	    AM_CODE(AM_PC) = B0;
43	    AM_PC = AM_PC + 1;
44	    AM_CODE(AM_PC) = B1;
45	    AM_PC = AM_PC + 1;
46	    AM_CODE(AM_PC) = B2;
47	    AM_PC = AM_PC + 1;
48	END;
49	
50	AM_PATCH_WORD: PROC(OFF INT, V INT);
51	    DCL B0 INT;
52	    DCL B1 INT;
53	    DCL B2 INT;
54	    DCL REM INT;
55	    REM = V;
56	    B2 = 0;
57	    DO WHILE (REM > 65535);
58	        REM = REM - 65536;
59	        B2 = B2 + 1;
60	    END;
61	    B1 = 0;
62	    DO WHILE (REM > 255);
63	        REM = REM - 256;
64	        B1 = B1 + 1;
65	    END;
66	    B0 = REM;
67	    AM_CODE(OFF) = B0;
68	    AM_CODE(OFF + 1) = B1;
69	    AM_CODE(OFF + 2) = B2;
70	END;
71	
72	/* ================================================================
73	 * Lowering: statement table -> AM bytecode
74	/* ================================================================ */
75	
76	/* N_OUT, N_INP, OUT_SYM, INP_SYM defined in sno_util + snoglob */
77	
78	
79	LOWER_STMT: PROC(S INT);
80	    DCL BR_OFF INT;
81	    DCL TGT INT;
82	
83	    STMT_ADDR(S) = AM_PC;
84	
85	    IF (S_TYP(S) = ST_END) THEN DO;
86	        CALL AM_EMIT_OP(OP_HALT);
87	        RETURN;
88	    END;
89	
90	    IF (S_TYP(S) = ST_EMPTY) THEN DO;
91	        CALL AM_EMIT_OP(OP_NOP);
92	        RETURN;
93	    END;
94	
95	    IF (S_TYP(S) = ST_ASSIGN) THEN DO;
96	        DCL EPI INT;
97	        DCL EPB INT;
98	        DCL EPT INT;
99	        DCL EPV INT;
100	
101	        /* Evaluate object expression */
102	        IF (S_EPCNT(S) = 2 AND EP_TYP(S * 4) = OE_ARRREF) THEN DO;
103	            /* Array ref: NAMES<I> */
104	            EPB = S * 4;
105	            EPT = EP_TYP(EPB + 1);
106	            EPV = EP_VAL(EPB + 1);
107	            IF (EPT = OE_IDENT) THEN DO;
108	                CALL AM_EMIT_OP(OP_LOAD_VAR);
109	                CALL AM_EMIT_BYTE(EPV);
110	            END;
111	            ELSE DO;
112	                CALL AM_EMIT_OP(OP_LOAD_INT);
113	                CALL AM_EMIT_WORD(EPV);
114	            END;
115	            CALL AM_EMIT_OP(OP_ARR_LOAD);
116	            CALL AM_EMIT_BYTE(EP_VAL(EPB));
117	        END;
118	        ELSE IF (S_EPCNT(S) >= 2 AND S_OEOP(S) = 0) THEN DO;
119	            /* Concatenation: emit parts with CONCAT between them */
120	            EPB = S * 4;
121	            EPI = 0;
122	            DO WHILE (EPI < S_EPCNT(S));
123	                EPT = EP_TYP(EPB + EPI);
124	                EPV = EP_VAL(EPB + EPI);
125	                IF (EPT = OE_INT) THEN DO;
126	                    CALL AM_EMIT_OP(OP_LOAD_INT);
127	                    CALL AM_EMIT_WORD(EPV);
128	                END;
129	                ELSE IF (EPT = OE_STR) THEN DO;
130	                    CALL AM_EMIT_OP(OP_LOAD_STR);
131	                    CALL AM_EMIT_WORD(EPV);
132	                END;
133	                ELSE IF (EPT = OE_IDENT) THEN DO;
134	                    IF (EPV = INP_SYM AND INP_SYM >= 0) THEN
135	                        CALL AM_EMIT_OP(OP_READ_INPUT);
136	                    ELSE DO;
137	                        CALL AM_EMIT_OP(OP_LOAD_VAR);
138	                        CALL AM_EMIT_BYTE(EPV);
139	                    END;
140	                END;
141	                ELSE IF (EPT = OE_ARRREF) THEN DO;
142	                    /* Next part is the index */
143	                    CALL AM_EMIT_OP(OP_ARR_LOAD);
144	                    CALL AM_EMIT_BYTE(EPV);
145	                    EPI = EPI + 1;
146	                    /* Skip the index part -- it's used by ARR_LOAD */
147	                END;
148	                ELSE IF (EPT = OE_FNCALL) THEN DO;
149	                    /* Next part is the arg */
150	                    DCL APT INT;
151	                    DCL APV INT;
152	                    EPI = EPI + 1;
153	                    APT = EP_TYP(EPB + EPI);
154	                    APV = EP_VAL(EPB + EPI);
155	                    IF (APT = OE_IDENT) THEN DO;
156	                        CALL AM_EMIT_OP(OP_LOAD_VAR);
157	                        CALL AM_EMIT_BYTE(APV);
158	                    END;
159	                    ELSE DO;
160	                        CALL AM_EMIT_OP(OP_LOAD_INT);
161	                        CALL AM_EMIT_WORD(APV);
162	                    END;
163	                    CALL AM_EMIT_OP(OP_CALL);
164	                    CALL AM_EMIT_BYTE(EPV);
165	                END;
166	                ELSE IF (EPT = OE_ARRAY) THEN DO;
167	                    CALL AM_EMIT_OP(OP_MAKE_ARRAY);
168	                END;
169	                IF (EPI > 0 AND EPT != OE_ARRREF AND EPT != OE_FNCALL) THEN
170	                    CALL AM_EMIT_OP(OP_CONCAT);
171	                EPI = EPI + 1;
172	            END;
173	        END;
174	        ELSE IF (S_OETY(S) = OE_INT) THEN DO;
175	            CALL AM_EMIT_OP(OP_LOAD_INT);
176	            CALL AM_EMIT_WORD(S_OEV1(S));
177	        END;
178	        ELSE IF (S_OETY(S) = OE_STR) THEN DO;
179	            CALL AM_EMIT_OP(OP_LOAD_STR);
180	            CALL AM_EMIT_WORD(S_SPTR(S));
181	        END;
182	        ELSE IF (S_OETY(S) = OE_IDENT) THEN DO;
183	            IF (S_OEV1(S) = INP_SYM AND INP_SYM >= 0) THEN
184	                CALL AM_EMIT_OP(OP_READ_INPUT);
185	            ELSE DO;
186	                CALL AM_EMIT_OP(OP_LOAD_VAR);
187	                CALL AM_EMIT_BYTE(S_OEV1(S));
188	            END;
189	        END;
190	        ELSE IF (S_OETY(S) = OE_BINOP) THEN DO;
191	            /* Emit first operand */
192	            EPB = S * 4;
193	            EPT = EP_TYP(EPB);
194	            EPV = EP_VAL(EPB);
195	            IF (EPT = OE_IDENT) THEN DO;
196	                CALL AM_EMIT_OP(OP_LOAD_VAR);
197	                CALL AM_EMIT_BYTE(EPV);
198	            END;
199	            ELSE DO;
200	                CALL AM_EMIT_OP(OP_LOAD_INT);
201	                CALL AM_EMIT_WORD(EPV);
202	            END;
203	            /* Emit second operand */
204	            EPT = EP_TYP(EPB + 1);
205	            EPV = EP_VAL(EPB + 1);
206	            IF (EPT = OE_IDENT) THEN DO;
207	                CALL AM_EMIT_OP(OP_LOAD_VAR);
208	                CALL AM_EMIT_BYTE(EPV);
209	            END;
210	            ELSE DO;
211	                CALL AM_EMIT_OP(OP_LOAD_INT);
212	                CALL AM_EMIT_WORD(EPV);
213	            END;
214	            /* Emit operator */
215	            IF (S_OEOP(S) = TK_PLUS) THEN
216	                CALL AM_EMIT_OP(OP_ADD);
217	            ELSE IF (S_OEOP(S) = TK_STAR) THEN
218	                CALL AM_EMIT_OP(OP_MUL);
219	            ELSE
220	                CALL AM_EMIT_OP(OP_SUB);
221	        END;
222	        ELSE IF (S_OETY(S) = OE_SPAN) THEN DO;
223	            CALL AM_EMIT_OP(OP_MAKE_SPAN);
224	            CALL AM_EMIT_WORD(S_SPTR(S));
225	        END;
226	        ELSE IF (S_EPCNT(S) = 1) THEN DO;
227	            EPB = S * 4;
228	            EPT = EP_TYP(EPB);
229	            EPV = EP_VAL(EPB);
230	            IF (EPT = OE_SPAN) THEN DO;
231	                CALL AM_EMIT_OP(OP_MAKE_SPAN);
232	                CALL AM_EMIT_WORD(EPV);
233	            END;
234	            ELSE IF (EPT = OE_ARRAY) THEN DO;
235	                CALL AM_EMIT_OP(OP_MAKE_ARRAY);
236	            END;
237	        END;
238	        ELSE IF (S_EPCNT(S) = 2 AND EP_TYP(S * 4) = OE_ARRREF) THEN DO;
239	            /* Single array ref: NAMES<I> or NAMES<3> */
240	            EPB = S * 4;
241	            EPT = EP_TYP(EPB + 1);
242	            EPV = EP_VAL(EPB + 1);
243	            IF (EPT = OE_IDENT) THEN DO;
244	                CALL AM_EMIT_OP(OP_LOAD_VAR);
245	                CALL AM_EMIT_BYTE(EPV);
246	            END;
247	            ELSE DO;
248	                CALL AM_EMIT_OP(OP_LOAD_INT);
249	                CALL AM_EMIT_WORD(EPV);
250	            END;
251	            CALL AM_EMIT_OP(OP_ARR_LOAD);
252	            CALL AM_EMIT_BYTE(EP_VAL(EPB));
253	        END;
254	
255	        /* Store */
256	        IF (S_SUBJ(S) >= 0) THEN DO;
257	            IF (S_SIDX(S) != 0 - 1) THEN DO;
258	                /* Array element store: NAMES<N> or NAMES<3> */
259	                IF (S_SIDX(S) >= 0) THEN DO;
260	                    /* Variable index */
261	                    CALL AM_EMIT_OP(OP_LOAD_VAR);
262	                    CALL AM_EMIT_BYTE(S_SIDX(S));
263	                END;
264	                ELSE DO;
265	                    /* Literal index (stored as -(val+1)) */
266	                    CALL AM_EMIT_OP(OP_LOAD_INT);
267	                    CALL AM_EMIT_WORD(0 - S_SIDX(S) - 1);
268	                END;
269	                CALL AM_EMIT_OP(OP_ARR_STORE);
270	                CALL AM_EMIT_BYTE(S_SUBJ(S));
271	            END;
272	            ELSE DO;
273	                CALL AM_EMIT_OP(OP_STORE_VAR);
274	                CALL AM_EMIT_BYTE(S_SUBJ(S));
275	            END;
276	        END;
277	
278	        /* OUTPUT print */
279	        IF (S_SUBJ(S) = OUT_SYM AND OUT_SYM >= 0) THEN DO;
280	            IF (S_OETY(S) = OE_STR AND S_EPCNT(S) < 2) THEN DO;
281	                CALL AM_EMIT_OP(OP_PRINT_STR);
282	                CALL AM_EMIT_WORD(S_SPTR(S));
283	            END;
284	            ELSE DO;
285	                /* Use PRINT_VAR for everything else (int, concat, ident) */
286	                CALL AM_EMIT_OP(OP_PRINT_VAR);
287	                CALL AM_EMIT_BYTE(S_SUBJ(S));
288	            END;
289	            CALL AM_EMIT_OP(OP_PRINT_NL);
290	        END;
291	
292	        /* Goto */
293	        IF (S_GTYP(S) = GT_UNCOND) THEN DO;
294	            CALL AM_EMIT_OP(OP_BR);
295	            CALL AM_EMIT_WORD(0);
296	        END;
297	        ELSE IF (S_GTYP(S) = GT_SUCC) THEN DO;
298	            CALL AM_EMIT_OP(OP_BR_SUCC);
299	            CALL AM_EMIT_WORD(0);
300	        END;
301	        ELSE IF (S_GTYP(S) = GT_FAIL) THEN DO;
302	            CALL AM_EMIT_OP(OP_BR_FAIL);
303	            CALL AM_EMIT_WORD(0);
304	        END;
305	        ELSE IF (S_GTYP(S) = GT_RET) THEN
306	            CALL AM_EMIT_OP(OP_RET);
307	        ELSE IF (S_GTYP(S) = GT_FRET) THEN
308	            CALL AM_EMIT_OP(OP_FRET);
309	    END;
310	
311	    IF (S_TYP(S) = ST_MATCH) THEN DO;
312	        IF (S_PPCNT(S) > 0) THEN DO;
313	            /* Compound pattern: emit build ops for each part,
314	             * then PAT_MATCH2 <subj_var> */
315	            DCL PPI2 INT;
316	            DCL PPB2 INT;
317	            DCL PPT INT;
318	            DCL PPV INT;
319	            PPB2 = S * 8;
320	            PPI2 = 0;
321	            DO WHILE (PPI2 < S_PPCNT(S));
322	                PPT = PP_TYP(PPB2 + PPI2);
323	                PPV = PP_VAL(PPB2 + PPI2);
324	                IF (PPT = OE_SPAN) THEN DO;
325	                    CALL AM_EMIT_OP(OP_MAKE_SPAN);
326	                    CALL AM_EMIT_WORD(PPV);
327	                END;
328	                ELSE IF (PPT = OE_BREAK) THEN DO;
329	                    CALL AM_EMIT_OP(OP_MAKE_BREAK);
330	                    CALL AM_EMIT_WORD(PPV);
331	                END;
332	                ELSE IF (PPT = OE_REM) THEN DO;
333	                    CALL AM_EMIT_OP(OP_MAKE_REM);
334	                END;
335	                ELSE IF (PPT = OE_STR) THEN DO;
336	                    CALL AM_EMIT_OP(OP_MAKE_LIT_PAT);
337	                    CALL AM_EMIT_WORD(PPV);
338	                END;
339	                ELSE IF (PPT = OE_IDENT) THEN DO;
340	                    /* Load pattern var value */
341	                    CALL AM_EMIT_OP(OP_LOAD_VAR);
342	                    CALL AM_EMIT_BYTE(PPV);
343	                END;
344	                ELSE IF (PPT = OE_CAP) THEN DO;
345	                    CALL AM_EMIT_OP(OP_PAT_CAP);
346	                    CALL AM_EMIT_BYTE(PPV);
347	                END;
348	                IF (PPI2 > 0 AND PPT != OE_CAP) THEN
349	                    CALL AM_EMIT_OP(OP_PAT_CONCAT);
350	                PPI2 = PPI2 + 1;
351	            END;
352	            CALL AM_EMIT_OP(OP_PAT_MATCH2);
353	            CALL AM_EMIT_BYTE(S_SUBJ(S));
354	        END;
355	        ELSE DO;
356	            /* Legacy simple match */
357	            CALL AM_EMIT_OP(OP_PAT_MATCH);
358	            CALL AM_EMIT_BYTE(S_SUBJ(S));
359	            CALL AM_EMIT_BYTE(S_OEV1(S));
360	            CALL AM_EMIT_BYTE(S_OEV2(S));
361	        END;
362	
363	        /* Goto after match */
364	        IF (S_GTYP(S) = GT_UNCOND) THEN DO;
365	            CALL AM_EMIT_OP(OP_BR);
366	            CALL AM_EMIT_WORD(0);
367	        END;
368	        ELSE IF (S_GTYP(S) = GT_SUCC) THEN DO;
369	            CALL AM_EMIT_OP(OP_BR_SUCC);
370	            CALL AM_EMIT_WORD(0);
371	        END;
372	        ELSE IF (S_GTYP(S) = GT_FAIL) THEN DO;
373	            CALL AM_EMIT_OP(OP_BR_FAIL);
374	            CALL AM_EMIT_WORD(0);
375	        END;
376	    END;
377	END;
378	
379	/* Fix up goto targets */
380	FIXUP_GOTOS: PROC;
381	    DCL I INT;
382	    DCL PC INT;
383	    DCL OP INT;
384	    DCL TGT INT;
385	
386	    PC = 0;
387	    DO WHILE (PC < AM_PC);
388	        OP = AM_CODE(PC);
389	        PC = PC + 1;
390	        IF (OP = OP_BR OR OP = OP_BR_SUCC OR OP = OP_BR_FAIL) THEN DO;
391	            /* Check if placeholder (0) needs fixup */
392	            TGT = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
393	            IF (TGT = 0) THEN DO;
394	                /* Find which statement has this goto */
395	                I = 0;
396	                DO WHILE (I < STCNT);
397	                    IF (S_GTYP(I) != GT_NONE AND S_GLBL(I) >= 0) THEN DO;
398	                        /* Check if this branch is for statement I */
399	                        /* The branch is at PC-1, find stmt with matching addr range */
400	                        IF (STMT_ADDR(I) <= PC - 1) THEN DO;
401	                            IF (I + 1 >= STCNT OR STMT_ADDR(I + 1) > PC - 1) THEN DO;
402	                                TGT = LBL_FIND(S_GLBL(I));
