            PSTOP = PSTOP + 1;
        END;
        ELSE IF (OP = OP_PAT_MATCH) THEN DO;
            /* PAT_MATCH <subj_var> <pat_var> <cap_var> */
            DCL SIDX INT;
            DCL PIDX INT;
            DCL CIDX INT;
            DCL SUBJ_OFF INT;
            DCL PAT_OFF INT;
            DCL SUBJ_LEN INT;
            DCL MATCHED INT;
            DCL TRYPOS INT;
            DCL MLEN INT;
            DCL SP2 PTR;
            DCL I INT;

            SIDX = AM_CODE(PC);
            PIDX = AM_CODE(PC + 1);
            CIDX = AM_CODE(PC + 2);
            PC = PC + 3;

            /* Subject is a string offset in SB */
            SUBJ_OFF = VARS(SIDX);
            /* Pattern var holds class string offset (from MAKE_SPAN) */
            PAT_OFF = VARS(PIDX);

            /* Get subject length */
            SUBJ_LEN = SLEN(ADDR(SB) + SUBJ_OFF);

            /* Try SPAN at each position (unanchored) */
            MATCHED = 0;
            TRYPOS = 0;
            DO WHILE (TRYPOS <= SUBJ_LEN AND MATCHED = 0);
                MLEN = EXEC_SPAN(ADDR(SB) + SUBJ_OFF, SUBJ_LEN, TRYPOS, ADDR(SB) + PAT_OFF);
                IF (MLEN > 0) THEN DO;
                    MATCHED = 1;
                    /* Store captured substring as string in SB */
                    IF (CIDX != 0 - 1 AND CIDX < 16) THEN DO;
                        /* Copy matched chars to SB */
                        DCL DST INT;
                        DST = SBPOS;
                        I = 0;
                        DO WHILE (I < MLEN);
                            SP2 = ADDR(SB) + SUBJ_OFF + TRYPOS + I;
                            DCL DP PTR;
                            DP = ADDR(SB) + SBPOS;
                            DP->DTAG = SP2->DTAG;
                            SBPOS = SBPOS + 1;
                            I = I + 1;
                        END;
                        DP = ADDR(SB) + SBPOS;
                        DP->DTAG = 0;
                        SBPOS = SBPOS + 1;
                        /* Store offset to captured string */
                        VARS(CIDX) = DST;
                        VTYP(CIDX) = VTYP_STR;
                    END;
                END;
                TRYPOS = TRYPOS + 1;
            END;

            LAST_RESULT = MATCHED;
        END;
        ELSE IF (OP = OP_MAKE_BREAK) THEN DO;
            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
            PC = PC + 3;
            /* Push (kind=BREAK, class_offset=V) onto pattern stack */
            PSTK(PSTOP) = V;
            PSTYP(PSTOP) = PK_BREAK;
            PSTOP = PSTOP + 1;
            LAST_PUSH_TYP = VTYP_PAT;
        END;
        ELSE IF (OP = OP_MAKE_REM) THEN DO;
            PSTK(PSTOP) = 0;
            PSTYP(PSTOP) = PK_REM;
            PSTOP = PSTOP + 1;
        END;
        ELSE IF (OP = OP_MAKE_LIT_PAT) THEN DO;
            V = AM_CODE(PC + 2) * 65536 + AM_CODE(PC + 1) * 256 + AM_CODE(PC);
            PC = PC + 3;
            PSTK(PSTOP) = V;
            PSTYP(PSTOP) = PK_LIT;
            PSTOP = PSTOP + 1;
        END;
        ELSE IF (OP = OP_PAT_CONCAT) THEN DO;
            /* Just a marker -- parts stay on pattern stack */
        END;
        ELSE IF (OP = OP_PAT_CAP) THEN DO;
            /* Mark previous pattern stack entry for capture */
            IDX = AM_CODE(PC);
            PC = PC + 1;
            /* Store capture var index with the previous part */
            IF (PSTOP > 0) THEN DO;
                /* Use high bit trick: val = val | (capvar << 16) -- too complex.
                 * Instead, add a capture entry to pattern stack */
                PSTK(PSTOP) = IDX;
                PSTYP(PSTOP) = PK_CAP;
                PSTOP = PSTOP + 1;
            END;
        END;
        ELSE IF (OP = OP_PAT_MATCH2) THEN DO;
            /* Execute compound pattern from pattern stack */
            DCL SIDX2 INT;
            DCL SUBJ_OFF2 INT;
            DCL SUBJ_LEN2 INT;
            DCL TRYPOS2 INT;
            DCL MATCHED2 INT;
            DCL CPOS INT;
            DCL PI INT;
            DCL PT INT;
            DCL PV INT;
            DCL MLEN2 INT;
            DCL CAPVAR INT;
            DCL CAPSTART INT;

            SIDX2 = AM_CODE(PC);
            PC = PC + 1;
            SUBJ_OFF2 = VARS(SIDX2);
            SUBJ_LEN2 = SLEN(ADDR(SB) + SUBJ_OFF2);

            MATCHED2 = 0;
            TRYPOS2 = 0;

            /* Try at each starting position (unanchored) */
            DO WHILE (TRYPOS2 <= SUBJ_LEN2 AND MATCHED2 = 0);
                CPOS = TRYPOS2;
                PI = 0;
                MATCHED2 = 1;
                CAPVAR = 0 - 1;

                DO WHILE (PI < PSTOP AND MATCHED2 = 1);
                    PT = PSTYP(PI);
                    PV = PSTK(PI);

                    IF (PT = PK_CAP) THEN DO;
                        /* Capture: store current substring into capture var */
                        IF (PV >= 0 AND PV < 16) THEN DO;
                            DCL DST2 INT;
                            DCL J INT;
                            DCL SP3 PTR;
                            DCL DP2 PTR;
                            DST2 = SBPOS;
                            J = CAPSTART;
                            DO WHILE (J < CPOS);
                                SP3 = ADDR(SB) + SUBJ_OFF2 + J;
                                DP2 = ADDR(SB) + SBPOS;
                                DP2->DTAG = SP3->DTAG;
                                SBPOS = SBPOS + 1;
                                J = J + 1;
                            END;
                            DP2 = ADDR(SB) + SBPOS;
                            DP2->DTAG = 0;
                            SBPOS = SBPOS + 1;
                            VARS(PV) = DST2;
                            VTYP(PV) = VTYP_STR;
                        END;
                    END;
                    ELSE IF (PT = PK_SPAN) THEN DO;
                        CAPSTART = CPOS;
                        MLEN2 = EXEC_SPAN(ADDR(SB) + SUBJ_OFF2, SUBJ_LEN2, CPOS, ADDR(SB) + PV);
                        IF (MLEN2 > 0) THEN
                            CPOS = CPOS + MLEN2;
                        ELSE
                            MATCHED2 = 0;
                    END;
                    ELSE IF (PT = PK_BREAK) THEN DO;
                        CAPSTART = CPOS;
                        MLEN2 = EXEC_BREAK(ADDR(SB) + SUBJ_OFF2, SUBJ_LEN2, CPOS, ADDR(SB) + PV);
                        IF (MLEN2 >= 0) THEN
                            CPOS = CPOS + MLEN2;
                        ELSE
                            MATCHED2 = 0;
                    END;
                    ELSE IF (PT = PK_REM) THEN DO;
                        CAPSTART = CPOS;
                        CPOS = SUBJ_LEN2;
                    END;
                    ELSE IF (PT = PK_LIT) THEN DO;
                        /* Literal match */
                        DCL LLEN INT;
                        DCL LK INT;
                        DCL LP2 PTR;
                        DCL CP2 PTR;
                        LLEN = SLEN(ADDR(SB) + PV);
                        IF (CPOS + LLEN > SUBJ_LEN2) THEN DO;
                            MATCHED2 = 0;
                        END;
                        ELSE DO;
                            LK = 0;
                            DO WHILE (LK < LLEN);
                                LP2 = ADDR(SB) + PV + LK;
                                CP2 = ADDR(SB) + SUBJ_OFF2 + CPOS + LK;
                                IF (LP2->DTAG != CP2->DTAG) THEN DO;
                                    MATCHED2 = 0;
                                    LK = LLEN;
                                END;
                                LK = LK + 1;
                            END;
                            IF (MATCHED2 = 1) THEN
                                CPOS = CPOS + LLEN;
                        END;
                    END;

                    PI = PI + 1;
                END;

                IF (MATCHED2 = 0) THEN
                    TRYPOS2 = TRYPOS2 + 1;
            END;

            PSTOP = 0;
            LAST_RESULT = MATCHED2;
        END;
        ELSE IF (OP = OP_MAKE_ARRAY) THEN DO;
            /* Allocate array, push array ID */
            V = ARR_CNT;
            ARR_CNT = ARR_CNT + 1;
            ESTK(ESP) = V;
            ESP = ESP + 1;
            LAST_PUSH_TYP = VTYP_ARR;
        END;
        ELSE IF (OP = OP_ARR_LOAD) THEN DO;
            /* ARR_LOAD <arr_var>: load arr[idx] where idx is in next LOAD_VAR.
             * Actually: arr_var tells which var holds the array ID.
             * The index comes from the NEXT instruction (LOAD_VAR for the index var).
             * Simpler: read arr_var, then read next byte as index_var. */
            DCL ARR_ID INT;
            DCL ARR_IDX INT;
            DCL ARR_VAR INT;
            DCL IDX_VAR INT;
            ARR_VAR = AM_CODE(PC);
            PC = PC + 1;
            ARR_ID = VARS(ARR_VAR);
            /* Index comes from eval stack (LOAD_VAR pushed it) */
            ESP = ESP - 1;
            ARR_IDX = ESTK(ESP);
            /* Load element */
            V = ARR_DATA(ARR_ID * 50 + ARR_IDX);
            ESTK(ESP) = V;
            ESP = ESP + 1;
            LAST_PUSH_TYP = VTYP_STR;
        END;
        ELSE IF (OP = OP_ARR_STORE) THEN DO;
            /* ARR_STORE <arr_var>: store val into arr[idx]
             * Stack: val, idx (idx on top from LOAD_VAR) */
            DCL AS_ARR INT;
            DCL AS_IDX INT;
            DCL AS_VAL INT;
            DCL AS_VAR INT;
            AS_VAR = AM_CODE(PC);
            PC = PC + 1;
            AS_ARR = VARS(AS_VAR);
            /* Pop index */
            ESP = ESP - 1;
            AS_IDX = ESTK(ESP);
            /* Pop value */
            ESP = ESP - 1;
            AS_VAL = ESTK(ESP);
            ARR_DATA(AS_ARR * 50 + AS_IDX) = AS_VAL;
        END;
        ELSE IF (OP = OP_READ_INPUT) THEN DO;
            /* Read one line from input data into SB */
            V = READ_INPUT();
            IF (V >= 0) THEN DO;
                ESTK(ESP) = V;
                ESP = ESP + 1;
                LAST_PUSH_TYP = VTYP_STR;
                LAST_RESULT = 1;
            END;
            ELSE DO;
                /* EOF -- push empty, set failure */
                ESTK(ESP) = 0;
                ESP = ESP + 1;
                LAST_PUSH_TYP = VTYP_STR;
                LAST_RESULT = 0;
            END;
        END;
        ELSE IF (OP = OP_CALL) THEN DO;
            /* OP_CALL <fn_idx>: arg already on ESTK; push frame, set param, jump */
            DCL FNI INT;
            DCL PSY INT;
            DCL ARG INT;
            FNI = AM_CODE(PC);
            PC = PC + 1;
            ESP = ESP - 1;
            ARG = ESTK(ESP);
            PSY = FN_PARAM(FNI);
            CSTK_PC(CSTK_TOP) = PC;
            CSTK_PV(CSTK_TOP) = VARS(PSY);
            CSTK_FN(CSTK_TOP) = FNI;
            CSTK_TOP = CSTK_TOP + 1;
            VARS(PSY) = ARG;
            VTYP(PSY) = VTYP_INT;
            /* Also clear function name var so caller sees fresh return */
            VARS(FN_NAME(FNI)) = 0;
            VTYP(FN_NAME(FNI)) = VTYP_INT;
            PC = STMT_ADDR(FN_ENTRY(FNI));
        END;
        ELSE IF (OP = OP_RET) THEN DO;
            DCL FNI2 INT;
            DCL PSY2 INT;
            CSTK_TOP = CSTK_TOP - 1;
            FNI2 = CSTK_FN(CSTK_TOP);
            PSY2 = FN_PARAM(FNI2);
            /* Push return value: function name var */
            ESTK(ESP) = VARS(FN_NAME(FNI2));
            ESP = ESP + 1;
            LAST_PUSH_TYP = VTYP(FN_NAME(FNI2));
            VARS(PSY2) = CSTK_PV(CSTK_TOP);
            PC = CSTK_PC(CSTK_TOP);
            LAST_RESULT = 1;
        END;
        ELSE IF (OP = OP_FRET) THEN DO;
            DCL FNI3 INT;
            DCL PSY3 INT;
            CSTK_TOP = CSTK_TOP - 1;
            FNI3 = CSTK_FN(CSTK_TOP);
            PSY3 = FN_PARAM(FNI3);
            ESTK(ESP) = 0;
            ESP = ESP + 1;
            LAST_PUSH_TYP = VTYP_INT;
            VARS(PSY3) = CSTK_PV(CSTK_TOP);
            PC = CSTK_PC(CSTK_TOP);
            LAST_RESULT = 0;
        END;
        ELSE IF (OP = OP_HALT) THEN DO;
            RETURN;
        END;
    END;
END;

/* ================================================================
 * Main: read -> parse -> lower -> execute via AM
/* ================================================================ */

/* Dummy MAIN for library compilation */
MAIN: PROC;
END;

