/* Identify SYM by name -> builtin code: 1=IDENT,2=DIFFER,3=GT,4=EQ,5=LE
 * 0 = not a builtin. Reads name bytes from SYMN. */
BLT_CODE: PROC(SIDX INT) RETURNS(INT);
    DCL NP PTR;
    DCL P1 PTR;
    DCL P2 PTR;
    DCL P3 PTR;
    DCL P4 PTR;
    DCL P5 PTR;
    NP = ADDR(SYMN) + SIDX * 8;
    P1 = NP + 1;
    P2 = NP + 2;
    P3 = NP + 3;
    P4 = NP + 4;
    P5 = NP + 5;
    /* IDENT */
    IF (NP->DTAG = 73) THEN IF (P1->DTAG = 68) THEN IF (P2->DTAG = 69) THEN
        IF (P3->DTAG = 78) THEN IF (P4->DTAG = 84) THEN IF (P5->DTAG = 0) THEN
            RETURN(1);
    /* DIFFER */
    IF (NP->DTAG = 68) THEN IF (P1->DTAG = 73) THEN IF (P2->DTAG = 70) THEN
        IF (P3->DTAG = 70) THEN IF (P4->DTAG = 69) THEN IF (P5->DTAG = 82) THEN
            RETURN(2);
    /* GT */
    IF (NP->DTAG = 71) THEN IF (P1->DTAG = 84) THEN IF (P2->DTAG = 0) THEN
        RETURN(3);
    /* EQ */
    IF (NP->DTAG = 69) THEN IF (P1->DTAG = 81) THEN IF (P2->DTAG = 0) THEN
        RETURN(4);
    /* LE */
    IF (NP->DTAG = 76) THEN IF (P1->DTAG = 69) THEN IF (P2->DTAG = 0) THEN
        RETURN(5);
    RETURN(0);
END;

FN_FIND: PROC(SIDX INT) RETURNS(INT);
    DCL I INT;
    I = 0;
    DO WHILE (I < FN_CNT);
        IF (FN_NAME(I) = SIDX) THEN RETURN(I);
        I = I + 1;
    END;
    RETURN(0 - 1);
END;

PARSE: PROC;
    DCL S INT;
    DCL NOFF INT;
    STCNT = 0;
    SBPOS = 0;
    SYMC = 0;
    LBLC = 0;
    FN_CNT = 0;
    SPOS = 0;
    AT_SOL = 1;
    CALL LEX;

    DO WHILE (TT != TK_EOF AND STCNT < STMAX);
        S = STCNT;
        S_TYP(S) = ST_EMPTY;
        S_SUBJ(S) = 0 - 1;
        S_OETY(S) = OE_NONE;
        S_OEV1(S) = 0;
        S_OEOP(S) = 0;
        S_OEV2(S) = 0;
        S_GTYP(S) = GT_NONE;
        S_GLBL(S) = 0 - 1;
        S_SPTR(S) = 0 - 1;
        S_EPCNT(S) = 0;
        S_PPCNT(S) = 0;
        S_SIDX(S) = 0 - 1;

        IF (TT = TK_EOL) THEN DO;
            CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE IF (TT = TK_IDENT AND IS_END() != 0) THEN DO;
            S_TYP(S) = ST_END;
            NOFF = SBSAVE();
            CALL LBL_ADD(NOFF, S);
            CALL LEX;
            IF (TT = TK_EOL) THEN CALL LEX;
            STCNT = STCNT + 1;
        END;
        ELSE IF (TT = TK_IDENT) THEN DO;
            IF (LHAS_LBL = 1) THEN DO;
