/* Parse function name and param from a "FNNAME(PARAM)" string in TB
 * Returns 0 on success. Registers entry in FN table with FN_ENTRY=-1. */
DEF_PARSE: PROC RETURNS(INT);
    DCL I INT;
    DCL J INT;
    DCL NOFF1 INT;
    DCL NOFF2 INT;
    DCL DP PTR;
    DCL C INT;
    DCL FNS INT;
    DCL PRS INT;
    IF (FN_CNT >= 4) THEN RETURN(0 - 1);
    /* Copy fn name into SB */
    NOFF1 = SBPOS;
    I = 0;
    C = TB(I);
    DO WHILE (C != 0 AND C != 40);
        DP = ADDR(SB) + SBPOS;
        DP->DTAG = C;
        SBPOS = SBPOS + 1;
        I = I + 1;
        C = TB(I);
    END;
    DP = ADDR(SB) + SBPOS;
    DP->DTAG = 0;
    SBPOS = SBPOS + 1;
    IF (C != 40) THEN RETURN(0 - 1);
    I = I + 1;
    /* Copy param name */
    NOFF2 = SBPOS;
    C = TB(I);
    DO WHILE (C != 0 AND C != 41);
        DP = ADDR(SB) + SBPOS;
        DP->DTAG = C;
        SBPOS = SBPOS + 1;
        I = I + 1;
        C = TB(I);
    END;
    DP = ADDR(SB) + SBPOS;
    DP->DTAG = 0;
    SBPOS = SBPOS + 1;
    FNS = SYM_LOOKUP(NOFF1);
    PRS = SYM_LOOKUP(NOFF2);
    FN_NAME(FN_CNT) = FNS;
    FN_NAMOFF(FN_CNT) = NOFF1;
    FN_PARAM(FN_CNT) = PRS;
    FN_ENTRY(FN_CNT) = 0 - 1;
    FN_CNT = FN_CNT + 1;
    RETURN(0);
END;

/* Identify SYM by name -> builtin code: 1=IDENT,2=DIFFER,3=GT,4=EQ,5=LE
